{
  "name": "Oil Paint ASMR Simulation",
  "description": "A meditative procedural oil painting simulator that recreates images stroke-by-stroke with authentic bristle textures and synchronized ASMR brush sounds.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Stroke {
  x: number;
  y: number;
  length: number;
  angle: number;
  width: number;
  color: string;
  opacity: number;
  pressure: number;
  stage: PaintingStage;
}

export enum PaintingStage {
  BACKGROUND_WASH = 'BACKGROUND_WASH',
  MIDGROUND_FORMS = 'MIDGROUND_FORMS',
  SUBJECT_DETAIL = 'SUBJECT_DETAIL',
  HIGHTLIGHT_IMPASTO = 'HIGHTLIGHT_IMPASTO'
}

export interface SimulationState {
  isPainting: boolean;
  progress: number;
  currentStage: PaintingStage;
  totalStrokes: number;
  renderedStrokes: number;
}

export class ASMRService {
  private audioCtx: AudioContext | null = null;
  private masterGain: GainNode | null = null;

  init() {
    if (this.audioCtx) return;
    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.audioCtx.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(this.audioCtx.destination);
  }

  playStrokeSound(x: number, width: number, pressure: number, duration: number) {
    if (!this.audioCtx || !this.masterGain) return;

    const panValue = (x / window.innerWidth) * 2 - 1;
    const panner = this.audioCtx.createStereoPanner();
    panner.pan.value = panValue;
    panner.connect(this.masterGain);

    const oscillator = this.audioCtx.createOscillator();
    const filter = this.audioCtx.createBiquadFilter();
    const noiseGain = this.audioCtx.createGain();

    // Create white noise for bristle scraping sound
    const bufferSize = 2 * this.audioCtx.sampleRate;
    const noiseBuffer = this.audioCtx.createBuffer(1, bufferSize, this.audioCtx.sampleRate);
    const output = noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      output[i] = Math.random() * 2 - 1;
    }

    const whiteNoise = this.audioCtx.createBufferSource();
    whiteNoise.buffer = noiseBuffer;
    whiteNoise.loop = true;

    // Filter noise to sound like bristles on canvas
    filter.type = 'bandpass';
    filter.frequency.value = 800 + (1 - pressure) * 2000;
    filter.Q.value = 1.0;

    noiseGain.gain.setValueAtTime(0, this.audioCtx.currentTime);
    noiseGain.gain.linearRampToValueAtTime(0.1 * pressure * (width / 20), this.audioCtx.currentTime + 0.05);
    noiseGain.gain.exponentialRampToValueAtTime(0.001, this.audioCtx.currentTime + duration);

    whiteNoise.connect(filter);
    filter.connect(noiseGain);
    noiseGain.connect(panner);

    whiteNoise.start();
    whiteNoise.stop(this.audioCtx.currentTime + duration);
  }

  suspend() {
    this.audioCtx?.suspend();
  }

  resume() {
    this.audioCtx?.resume();
  }
}

export const asmrService = new ASMRService();

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeAndPlanPainting(imageBuffer: string) {
  const prompt = `
    Analyze this image as a master oil painter. 
    1. Identify the composition layers: background, midground, foreground subject.
    2. Extract dominant colors for each layer.
    3. Determine the "flow" of forms (stroke directions).
    4. Provide a sequence of brush strokes to reconstruct this image realistically.

    Return a JSON object with:
    - palette: array of hex colors
    - strokePlan: array of stroke clusters, each with a 'stage' (BACKGROUND_WASH, MIDGROUND_FORMS, SUBJECT_DETAIL, HIGHTLIGHT_IMPASTO) and suggested density.
    - focalPoint: {x, y} normalized 0-1.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: imageBuffer, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER }
            }
          },
          strokePlan: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stage: { type: Type.STRING },
                density: { type: Type.NUMBER },
                averageColor: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.BACKGROUND_WASH,
    totalStrokes: 5000,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const offscreenCanvasRef = useRef<HTMLCanvasElement | null>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setImage(event.target?.result as string);
      startSimulation(base64);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      const generatedStrokes = generateProceduralStrokes(analysis, 5000);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length
      }));

      // Clear canvas
      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d');
        ctx?.clearRect(0, 0, canvas.width, canvas.height);
        // Fill canvas with light beige primer
        if (ctx) {
          ctx.fillStyle = '#f5f5dc';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
        }
      }
    } catch (error) {
      console.error("Simulation initialization failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      PaintingStage.BACKGROUND_WASH,
      PaintingStage.MIDGROUND_FORMS,
      PaintingStage.SUBJECT_DETAIL,
      PaintingStage.HIGHTLIGHT_IMPASTO
    ];

    stages.forEach((stage, sIdx) => {
      const stageCount = Math.floor(count * (0.4 - sIdx * 0.1));
      for (let i = 0; i < stageCount; i++) {
        const x = Math.random();
        const y = Math.random();

        // Pick a color from palette or jitter near average
        const color = analysis.palette[Math.floor(Math.random() * analysis.palette.length)];

        strokes.push({
          x,
          y,
          length: stage === PaintingStage.BACKGROUND_WASH ? 0.2 + Math.random() * 0.3 : 0.05 + Math.random() * 0.1,
          angle: Math.random() * Math.PI * 2,
          width: stage === PaintingStage.BACKGROUND_WASH ? 40 + Math.random() * 60 : 5 + Math.random() * 15,
          color,
          opacity: stage === PaintingStage.BACKGROUND_WASH ? 0.3 : 0.8,
          pressure: 0.3 + Math.random() * 0.7,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const w = canvasRef.current!.width;
    const h = canvasRef.current!.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';

    // Simulate bristle texture with multiple sub-strokes
    const bristles = Math.floor(stroke.width / 2);
    for (let j = 0; j < bristles; j++) {
      const offset = (j - bristles / 2) * 1.5;
      const jitterX = (Math.random() - 0.5) * 2;
      const jitterY = (Math.random() - 0.5) * 2;

      ctx.beginPath();
      ctx.strokeStyle = stroke.color;
      ctx.globalAlpha = stroke.opacity * (0.5 + Math.random() * 0.5);
      ctx.lineWidth = 1 + Math.random() * 2;

      ctx.moveTo(startX + offset + jitterX, startY + offset + jitterY);
      ctx.lineTo(endX + offset + jitterX, endY + offset + jitterY);
      ctx.stroke();
    }

    // Add "Impasto" highlight to simulate paint thickness
    if (stroke.stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.lineWidth = 1;
      ctx.moveTo(startX, startY);
      ctx.lineTo(endX, endY);
      ctx.stroke();
    }

    ctx.restore();

    // Trigger ASMR sound
    const duration = 0.1 + stroke.length * 0.5;
    asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, duration);
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false }));
      return;
    }

    // Render a small batch of strokes per frame to feel natural
    const batchSize = simState.currentStage === PaintingStage.BACKGROUND_WASH ? 1 : 2;
    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);

      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#0a0a0a] text-white">
      {/* Header */}
      <header className="p-4 border-b border-white/10 flex justify-between items-center bg-[#121212] z-10 shadow-xl">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-amber-600 rounded-full flex items-center justify-center">
            <i className="fas fa-palette text-white"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">Studio Painter</h1>
            <p className="text-xs text-zinc-500 uppercase tracking-widest">ASMR Simulation Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          {!simState.isPainting && !isAnalyzing && (
            <label className="bg-amber-600 hover:bg-amber-500 text-white px-6 py-2 rounded-full cursor-pointer transition-all font-medium flex items-center gap-2">
              <i className="fas fa-upload"></i>
              Start Session
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end">
              <span className="text-xs text-zinc-400 font-mono">
                {simState.currentStage.replace('_', ' ')}
              </span>
              <div className="w-48 h-1 bg-zinc-800 rounded-full mt-1 overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-300"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 relative flex items-center justify-center p-8 bg-[#0a0a0a]">
        {/* The Canvas */}
        <div className="relative shadow-2xl border-[12px] border-[#1a1a1a] rounded-sm overflow-hidden bg-white/5 group">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[80vh] shadow-inner"
          />

          {/* Overlay for Initial State */}
          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#121212] text-zinc-500 p-10 text-center">
              <i className="fas fa-image text-6xl mb-4 opacity-20"></i>
              <p className="max-w-xs text-sm leading-relaxed">
                Upload a photograph to begin the meditative oil painting process. 
                Ensure your sound is on for the ASMR experience.
              </p>
            </div>
          )}

          {/* Analyzing State */}
          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 backdrop-blur-md z-20">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-amber-600/20 border-t-amber-600 rounded-full animate-spin"></div>
              </div>
              <p className="mt-4 text-amber-500 font-medium tracking-widest text-sm animate-pulse">
                PLANNING STROKES...
              </p>
            </div>
          )}
        </div>

        {/* Floating Controls */}
        <div className="absolute bottom-8 right-8 flex gap-4">
          <button 
            onClick={() => asmrService.resume()}
            className="w-12 h-12 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 flex items-center justify-center transition-all"
            title="Enable Audio"
          >
            <i className="fas fa-volume-up"></i>
          </button>
        </div>
      </main>

      {/* Footer Status Bar */}
      <footer className="h-10 bg-[#121212] border-t border-white/5 flex items-center px-4 justify-between text-[10px] text-zinc-500 uppercase tracking-widest font-mono">
        <div className="flex gap-4">
          <span>Simulation Mode: Procedural Oil</span>
          <span>Sample Rate: 24kHz</span>
        </div>
        <div>
          {simState.isPainting ? (
            <span className="text-amber-500">Strokes: {simState.renderedStrokes.toLocaleString()} / {simState.totalStrokes.toLocaleString()}</span>
          ) : (
            <span>Engine Ready</span>
          )}
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeAndPlanPainting(imageBuffer: string) {
  const prompt = `
    Analyze this image as a master oil painter. 
    1. Identify the composition layers: background, midground, foreground subject.
    2. Divide the image into a 4x4 grid and identify the dominant colors and prominent edge directions in each quadrant.
    3. Extract a high-fidelity palette of at least 12 colors from the image.
    4. Provide a sequence plan to reconstruct this image realistically with significant detail.

    Return a JSON object with:
    - palette: array of hex colors
    - strokePlan: array of stroke clusters, each with a 'stage' (BACKGROUND_WASH, MIDGROUND_FORMS, SUBJECT_DETAIL, HIGHTLIGHT_IMPASTO) and suggested density.
    - focalPoint: {x, y} normalized 0-1.
    - quadrantColors: array of objects {x, y, color} mapping the image's color structure.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: imageBuffer, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER }
            }
          },
          quadrantColors: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING }
              }
            }
          },
          strokePlan: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stage: { type: Type.STRING },
                density: { type: Type.NUMBER },
                averageColor: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
}

import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const STROKE_COUNT = 18000; // Significantly increased for detail

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.BACKGROUND_WASH,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setImage(event.target?.result as string);
      startSimulation(base64);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#e6e1d5'; // Natural canvas primer color
          ctx.fillRect(0, 0, canvas.width, canvas.height);
        }
      }
    } catch (error) {
      console.error("Simulation initialization failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.15 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.25 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.45 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.15 }
    ];

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);
      for (let i = 0; i < stageCount; i++) {
        // Importance sampling: Bias towards focal point for details
        let x, y;
        if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
          const bias = 0.6;
          x = Math.random() < bias ? analysis.focalPoint.x + (Math.random() - 0.5) * 0.4 : Math.random();
          y = Math.random() < bias ? analysis.focalPoint.y + (Math.random() - 0.5) * 0.4 : Math.random();
        } else {
          x = Math.random();
          y = Math.random();
        }

        // Clamp to 0-1
        x = Math.max(0, Math.min(1, x));
        y = Math.max(0, Math.min(1, y));

        // Find nearest quadrant color if available
        let color = analysis.palette[Math.floor(Math.random() * analysis.palette.length)];
        if (analysis.quadrantColors && analysis.quadrantColors.length > 0) {
            let minDist = Infinity;
            analysis.quadrantColors.forEach((qc: any) => {
                const d = Math.sqrt(Math.pow(x - qc.x, 2) + Math.pow(y - qc.y, 2));
                if (d < minDist) {
                    minDist = d;
                    color = qc.color;
                }
            });
            // Add slight color jitter
            if (Math.random() > 0.7) {
                color = analysis.palette[Math.floor(Math.random() * analysis.palette.length)];
            }
        }

        strokes.push({
          x,
          y,
          length: stage === PaintingStage.BACKGROUND_WASH ? 0.15 + Math.random() * 0.2 : 
                  stage === PaintingStage.MIDGROUND_FORMS ? 0.05 + Math.random() * 0.1 :
                  0.01 + Math.random() * 0.04,
          angle: Math.random() * Math.PI * 2,
          width: stage === PaintingStage.BACKGROUND_WASH ? 50 + Math.random() * 70 : 
                 stage === PaintingStage.MIDGROUND_FORMS ? 15 + Math.random() * 20 :
                 3 + Math.random() * 8,
          color,
          opacity: stage === PaintingStage.BACKGROUND_WASH ? 0.4 : 0.85,
          pressure: 0.4 + Math.random() * 0.6,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const w = canvasRef.current!.width;
    const h = canvasRef.current!.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    // Simulate real oil drag with a series of tiny overlaps
    const steps = 3;
    for (let s = 0; s < steps; s++) {
      const stepAlpha = (1 - s/steps) * stroke.opacity;
      const bristles = Math.floor(stroke.width / 1.5);

      for (let j = 0; j < bristles; j++) {
        const offset = (j - bristles / 2) * 1.2;
        const noise = (Math.random() - 0.5) * 2;

        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.globalAlpha = stepAlpha * (0.4 + Math.random() * 0.6);
        ctx.lineWidth = 0.8 + Math.random() * 1.5;
        ctx.lineCap = 'round';

        ctx.moveTo(startX + offset + noise, startY + offset + noise);
        ctx.lineTo(endX + offset + noise, endY + offset + noise);
        ctx.stroke();
      }
    }

    // Impasto highlight (rim light on paint edge)
    if (stroke.stage === PaintingStage.HIGHTLIGHT_IMPASTO || (stroke.stage === PaintingStage.SUBJECT_DETAIL && stroke.pressure > 0.8)) {
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(255,255,255,0.15)';
      ctx.lineWidth = 0.5;
      ctx.globalAlpha = 0.3;
      ctx.moveTo(startX - 1, startY - 1);
      ctx.lineTo(endX - 1, endY - 1);
      ctx.stroke();
    }

    ctx.restore();

    // Occasional ASMR sound to prevent audio overload with high stroke count
    if (Math.random() > 0.7 || stroke.stage === PaintingStage.BACKGROUND_WASH) {
      const duration = 0.05 + stroke.length * 0.3;
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, duration);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    // Dynamic speed: Background is fast, detail is slow and deliberate
    const batchSize = simState.currentStage === PaintingStage.BACKGROUND_WASH ? 20 : 
                      simState.currentStage === PaintingStage.MIDGROUND_FORMS ? 10 : 5;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);

      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    const newProgress = (simulationRef.current.currentIndex / strokes.length) * 100;

    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: newProgress
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#0a0a0a] text-white">
      <header className="p-4 border-b border-white/10 flex justify-between items-center bg-[#121212] z-10 shadow-xl">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-amber-600 rounded-full flex items-center justify-center">
            <i className="fas fa-palette text-white"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">Master Studio</h1>
            <p className="text-xs text-zinc-500 uppercase tracking-widest">High-Fidelity Oil Simulation</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          {!simState.isPainting && !isAnalyzing && (
            <label className="bg-amber-600 hover:bg-amber-500 text-white px-8 py-2.5 rounded-full cursor-pointer transition-all font-medium flex items-center gap-2 shadow-lg hover:shadow-amber-600/20">
              <i className="fas fa-paint-brush"></i>
              REPAINT SOURCE
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end">
              <span className="text-[10px] text-amber-500 font-mono tracking-widest mb-1">
                {simState.currentStage.replace('_', ' ')}
              </span>
              <div className="w-64 h-1.5 bg-zinc-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-300 shadow-[0_0_10px_rgba(245,158,11,0.5)]"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center p-12 bg-[#0d0d0d] overflow-hidden">
        <div className="absolute inset-0 opacity-20 pointer-events-none">
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,_rgba(40,40,40,1)_0%,_rgba(10,10,10,1)_100%)]"></div>
        </div>

        <div className="relative shadow-[0_50px_100px_-20px_rgba(0,0,0,0.8)] border-[16px] border-[#1c1c1c] rounded-sm overflow-hidden bg-[#222]">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[75vh] block"
          />

          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#121212] text-zinc-400 p-12 text-center">
              <div className="w-24 h-24 mb-6 rounded-full border-2 border-dashed border-zinc-700 flex items-center justify-center opacity-40">
                <i className="fas fa-plus text-3xl"></i>
              </div>
              <h2 className="text-lg font-medium text-zinc-200 mb-2">Ready for Commission</h2>
              <p className="max-w-md text-sm leading-relaxed opacity-60">
                Upload a photo to watch it be painstakingly recreated stroke-by-stroke. 
                Experience over 18,000 individual brush movements with spatial ASMR.
              </p>
            </div>
          )}

          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm z-20">
              <div className="w-20 h-20 relative">
                <div className="absolute inset-0 border-4 border-amber-600/10 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-t-amber-600 rounded-full animate-spin"></div>
              </div>
              <p className="mt-6 text-amber-500 font-bold tracking-[0.3em] text-xs uppercase">
                Studying Composition
              </p>
              <p className="mt-2 text-zinc-500 text-[10px] animate-pulse">Mapping colors and forms...</p>
            </div>
          )}
        </div>

        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-4 px-6 py-3 bg-[#1a1a1a]/80 backdrop-blur-xl border border-white/5 rounded-full shadow-2xl transition-opacity hover:opacity-100 opacity-60">
          <button onClick={() => asmrService.resume()} className="flex items-center gap-2 text-[10px] font-bold tracking-widest uppercase hover:text-amber-500 transition-colors">
            <i className="fas fa-headphones-alt"></i> Sound On
          </button>
          <div className="w-px h-4 bg-white/10 my-auto"></div>
          <div className="text-[10px] font-bold tracking-widest uppercase text-zinc-500">
            {simState.isPainting ? `Rendering detail...` : `Idle`}
