              <span className="text-amber-600/80">Batch: {simState.currentStage === PaintingStage.BACKGROUND_WASH ? 'Wide' : 'Fine'}</span>
              <span className="text-zinc-400">Prog: {Math.floor(simState.progress)}%</span>
            </>
          )}
          <span className="bg-zinc-900 px-3 py-1 rounded border border-white/5">1280x720 RAW</span>
