import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeAndPlanPainting(imageBuffer: string) {
  const prompt = `
    Perform a professional artistic deconstruction of this image for an oil painting reproduction.
    1. Create an 8x8 spatial color map. For each cell in the 8x8 grid (64 total), provide the dominant hex color and primary angle.
    2. Identify the 'Edge Flow': the primary orientation of lines in each 8x8 cell (0-360 degrees).
    3. Identify the Primary Focal Point (x,y) and its specific high-contrast detail colors.
    4. Specify the overall 'Temperature' and 'Lighting Direction'.

    CRITICAL: You MUST return exactly 64 items in the colorGrid array, representing an 8x8 grid.

    Return a JSON object with:
    - palette: array of 16 key hex colors.
    - colorGrid: array of 64 objects {x, y, color, angle}.
    - focalPoint: {x, y, detailColors: []}.
    - lighting: {direction: string, intensity: number}.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: imageBuffer, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER },
              detailColors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["x", "y", "detailColors"]
          },
          colorGrid: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING },
                angle: { type: Type.NUMBER }
              },
              required: ["x", "y", "color", "angle"]
            }
          },
          lighting: {
            type: Type.OBJECT,
            properties: {
              direction: { type: Type.STRING },
              intensity: { type: Type.NUMBER }
            }
          }
        },
        required: ["palette", "focalPoint", "colorGrid"]
      }
    }
  });

  return JSON.parse(response.text);
}

import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const STROKE_COUNT = 35000; // Ultra high fidelity

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.BACKGROUND_WASH,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setImage(event.target?.result as string);
      startSimulation(base64);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      if (!analysis || !analysis.colorGrid) {
        throw new Error("Invalid analysis data received from Gemini");
      }

      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#dcd5c5'; // Gesso primed canvas
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          // Canvas texture overlay
          ctx.globalAlpha = 0.05;
          ctx.fillStyle = '#000000';
          for(let i=0; i<canvas.width; i+=4) {
             ctx.fillRect(i, 0, 1, canvas.height);
             ctx.fillRect(0, i, canvas.width, 1);
          }
          ctx.globalAlpha = 1.0;
        }
      }
    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Failed to analyze image. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.12 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.28 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.50 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const palette = analysis.palette || ['#000000'];
    const colorGrid = analysis.colorGrid || [];
    const focalPoint = analysis.focalPoint || { x: 0.5, y: 0.5, detailColors: ['#ffffff'] };

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);
      for (let i = 0; i < stageCount; i++) {
        let x = Math.random();
        let y = Math.random();

        // Subject Detail concentration
        if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
          const focusWeight = 0.7;
          if (Math.random() < focusWeight) {
            x = focalPoint.x + (Math.random() - 0.5) * 0.3;
            y = focalPoint.y + (Math.random() - 0.5) * 0.3;
          }
        }

        x = Math.max(0, Math.min(1, x));
        y = Math.max(0, Math.min(1, y));

        // Spatial Color and Flow Interpolation
        let bestColor = palette[0];
        let bestAngle = Math.random() * Math.PI * 2;
        let minDist = Infinity;

        if (colorGrid.length > 0) {
          colorGrid.forEach((cell: any) => {
            const d = Math.pow(x - cell.x, 2) + Math.pow(y - cell.y, 2);
            if (d < minDist) {
              minDist = d;
              bestColor = cell.color;
              bestAngle = (cell.angle * Math.PI) / 180;
            }
          });
        }

        // Focal point overrides for extreme highlights
        if (stage === PaintingStage.HIGHTLIGHT_IMPASTO && Math.random() > 0.5) {
            const details = focalPoint.detailColors || ['#ffffff'];
            bestColor = details[Math.floor(Math.random() * details.length)];
        }

        strokes.push({
          x,
          y,
          length: stage === PaintingStage.BACKGROUND_WASH ? 0.1 + Math.random() * 0.15 : 
                  stage === PaintingStage.MIDGROUND_FORMS ? 0.03 + Math.random() * 0.06 :
                  0.005 + Math.random() * 0.02,
          angle: bestAngle + (Math.random() - 0.5) * 0.4, // Follow edge flow with jitter
          width: stage === PaintingStage.BACKGROUND_WASH ? 60 + Math.random() * 40 : 
                 stage === PaintingStage.MIDGROUND_FORMS ? 12 + Math.random() * 15 :
                 2 + Math.random() * 5,
          color: bestColor,
          opacity: stage === PaintingStage.BACKGROUND_WASH ? 0.5 : 0.9,
          pressure: 0.5 + Math.random() * 0.5,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const w = canvasRef.current!.width;
    const h = canvasRef.current!.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    const passes = stroke.stage === PaintingStage.BACKGROUND_WASH ? 1 : 2;
    for(let p = 0; p < passes; p++) {
        const bristles = Math.max(1, Math.floor(stroke.width / 1.8));
        for (let j = 0; j < bristles; j++) {
            const offset = (j - bristles / 2) * 1.3;
            const noise = (Math.random() - 0.5) * 1.5;

            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity * (0.3 + Math.random() * 0.7);
            ctx.lineWidth = 0.5 + Math.random() * 1.2;
            ctx.lineCap = 'round';

            ctx.moveTo(startX + offset + noise, startY + offset + noise);
            ctx.lineTo(endX + offset + noise, endY + offset + noise);
            ctx.stroke();
        }
    }

    if (stroke.width > 5) {
        ctx.beginPath();
        ctx.strokeStyle = 'rgba(0,0,0,0.05)';
        ctx.lineWidth = 0.5;
        ctx.moveTo(startX + 1, startY + 1);
        ctx.lineTo(endX + 1, endY + 1);
        ctx.stroke();

        ctx.beginPath();
        ctx.strokeStyle = 'rgba(255,255,255,0.08)';
        ctx.lineWidth = 0.5;
        ctx.moveTo(startX - 1, startY - 1);
        ctx.lineTo(endX - 1, endY - 1);
        ctx.stroke();
    }

    ctx.restore();

    if (Math.random() > 0.92 || stroke.width > 30) {
      const duration = 0.04 + stroke.length * 0.2;
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, duration);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const batchSize = simState.currentStage === PaintingStage.BACKGROUND_WASH ? 50 : 
                      simState.currentStage === PaintingStage.MIDGROUND_FORMS ? 35 : 15;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);

      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 selection:bg-amber-500/30">
      <header className="px-6 py-4 border-b border-white/5 flex justify-between items-center bg-[#0d0d0d]/80 backdrop-blur-md z-30 sticky top-0">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-amber-600 to-amber-800 rounded-lg flex items-center justify-center shadow-lg rotate-3">
            <i className="fas fa-brush text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter italic">V-RENDER OIL</h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.3em] font-bold">Ultra-Fidelity Studio</p>
          </div>
        </div>

        <div className="flex items-center gap-8">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-zinc-100 hover:bg-amber-500 text-black px-10 py-3 rounded-sm cursor-pointer transition-all font-black text-xs tracking-widest flex items-center gap-3">
              <i className="fas fa-file-import group-hover:scale-110 transition-transform"></i>
              BEGIN COMMISSION
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end w-72">
              <div className="flex justify-between w-full mb-2">
                <span className="text-[10px] text-amber-500 font-black tracking-[0.2em] uppercase">
                  {simState.currentStage.replace('_', ' ')}
                </span>
                <span className="text-[10px] text-zinc-500 font-mono">{Math.floor(simState.progress)}%</span>
              </div>
              <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-300 shadow-[0_0_15px_rgba(245,158,11,0.8)]"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center bg-[#080808] p-4 lg:p-12 overflow-hidden">
        <div className="relative shadow-[0_80px_160px_-40px_rgba(0,0,0,0.9)] border-[20px] border-[#111] rounded-[2px] overflow-hidden bg-[#1a1a1a]">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[72vh] block object-contain"
          />

          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#0a0a0a] p-16 text-center">
              <div className="w-32 h-32 mb-8 relative">
                 <div className="absolute inset-0 bg-amber-500/5 rounded-full animate-ping"></div>
                 <div className="relative w-full h-full rounded-full border border-white/10 flex items-center justify-center">
                  <i className="fas fa-cloud-upload-alt text-4xl opacity-20"></i>
                 </div>
              </div>
              <h2 className="text-2xl font-black text-zinc-100 mb-4 tracking-tight text-white">WAITING FOR INPUT</h2>
              <p className="max-w-md text-xs leading-relaxed text-zinc-500 font-medium uppercase tracking-widest">
                Analyzing spatial color grids & edge flow for pixel-perfect reproduction. 
                35,000+ custom bristle movements.
              </p>
            </div>
          )}

          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 backdrop-blur-xl z-20">
              <div className="flex gap-1 mb-8">
                {[...Array(5)].map((_,i) => (
                  <div key={i} className="w-1.5 h-1.5 bg-amber-500 animate-bounce" style={{animationDelay: `${i*0.1}s`}}></div>
                ))}
              </div>
              <p className="text-amber-500 font-black tracking-[0.5em] text-[10px] uppercase">
                Deconstructing Visual Semantics
              </p>
            </div>
          )}
        </div>

        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-6 px-8 py-4 bg-[#0d0d0d]/90 border border-white/5 rounded-full shadow-2xl">
          <button onClick={() => asmrService.resume()} className="flex items-center gap-3 text-[10px] font-black tracking-widest uppercase text-amber-500 hover:text-amber-400 transition-colors">
            <i className="fas fa-headphones text-lg text-amber-500"></i> SPATIAL ASMR
          </button>
          <div className="w-px h-6 bg-white/10"></div>
          <div className="text-[10px] font-black tracking-widest uppercase text-zinc-600">
            {simState.isPainting ? `Rendering 35k strokes` : `System Idle`}
          </div>
        </div>
      </main>

      <footer className="h-14 bg-[#050505] border-t border-white/5 flex items-center px-8 justify-between text-[10px] text-zinc-500 uppercase tracking-[0.2em] font-black">
        <div className="flex gap-12">
          <div className="flex items-center gap-3">
            <span className="w-2 h-2 rounded-full bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,1)]"></span>
            <span>Grid: 8x8 Sampling</span>
          </div>
          <span>Physics: Viscous Oil Drag</span>
        </div>
        <div className="flex gap-8 items-center">
          {simState.isPainting && (
            <>
              <span className="text-zinc-400">Total: {simState.renderedStrokes.toLocaleString()}</span>
            </>
          )}
          <span className="bg-zinc-900/50 px-4 py-1.5 rounded-sm border border-white/5 text-zinc-400">720p 16:9 PRO</span>
        </div>
      </footer>
    </div>
  );
};

