import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeAndPlanPainting(imageBuffer: string) {
  const prompt = `
    Perform a professional artistic deconstruction of this image for an oil painting reproduction with a focus on structural accuracy (Edge Detection).

    1. Create an 8x8 spatial color map. For each cell (64 total), provide the dominant hex color.
    2. EDGE DETECTION: Identify the 'Flow Vectors' for each cell. If a cell contains a strong edge (e.g., the side of a face, a horizon, or a tree branch), specify the precise angle of that edge (0-360).
    3. FEATURE MAPPING: Identify high-frequency detail areas (eyes, sharp edges, text, small objects) and provide their specific (x,y) coordinates and local colors.
    4. Focal Point: Pinpoint the exact visual center of interest.

    CRITICAL: You MUST return exactly 64 items in the colorGrid array. Ensure the 'angle' property reflects the actual structural flow of the image in that sector.

    Return a JSON object with:
    - palette: array of 16 key hex colors.
    - colorGrid: array of 64 objects {x, y, color, angle}.
    - features: array of 10-15 objects {x, y, color, importance} for sharp edge/detail placement.
    - focalPoint: {x, y, detailColors: []}.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: imageBuffer, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER },
              detailColors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["x", "y", "detailColors"]
          },
          features: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING },
                importance: { type: Type.NUMBER }
              }
            }
          },
          colorGrid: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING },
                angle: { type: Type.NUMBER }
              },
              required: ["x", "y", "color", "angle"]
            }
          }
        },
        required: ["palette", "focalPoint", "colorGrid", "features"]
      }
    }
  });

  return JSON.parse(response.text);
}

import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const STROKE_COUNT = 45000; // Pushing density for edge precision

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.BACKGROUND_WASH,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setImage(event.target?.result as string);
      startSimulation(base64);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      if (!analysis || !analysis.colorGrid) {
        throw new Error("Invalid analysis data");
      }

      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#d6cfbd'; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          // Prime with basic texture
          ctx.globalAlpha = 0.08;
          ctx.fillStyle = '#000';
          for(let i=0; i<canvas.width; i+=5) ctx.fillRect(i, 0, 1, canvas.height);
          for(let i=0; i<canvas.height; i+=5) ctx.fillRect(0, i, canvas.width, 1);
          ctx.globalAlpha = 1.0;
        }
      }
    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Analysis failed. Please try a different image.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.10 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.25 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.55 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const palette = analysis.palette || ['#000000'];
    const colorGrid = analysis.colorGrid || [];
    const features = analysis.features || [];
    const focalPoint = analysis.focalPoint || { x: 0.5, y: 0.5, detailColors: ['#fff'] };

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);
      for (let i = 0; i < stageCount; i++) {
        let x, y;

        // EDGE AND FEATURE SAMPLING:
        // For detail stages, we sample heavily from the detected feature coordinates
        if ((stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) && features.length > 0 && Math.random() < 0.6) {
           const feature = features[Math.floor(Math.random() * features.length)];
           x = feature.x + (Math.random() - 0.5) * 0.05;
           y = feature.y + (Math.random() - 0.5) * 0.05;
        } else {
           x = Math.random();
           y = Math.random();
           // Concentration near focal point
           if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
              const bias = 0.75;
              if (Math.random() < bias) {
                x = focalPoint.x + (Math.pow(Math.random(), 3) * (Math.random() < 0.5 ? 1 : -1)) * 0.4;
                y = focalPoint.y + (Math.pow(Math.random(), 3) * (Math.random() < 0.5 ? 1 : -1)) * 0.4;
              }
           }
        }

        x = Math.max(0, Math.min(1, x));
        y = Math.max(0, Math.min(1, y));

        // Spatial Grid Analysis for local flow and color
        let bestColor = palette[0];
        let bestAngle = Math.random() * Math.PI * 2;
        let minDist = Infinity;

        if (colorGrid.length > 0) {
          colorGrid.forEach((cell: any) => {
            const d = Math.pow(x - cell.x, 2) + Math.pow(y - cell.y, 2);
            if (d < minDist) {
              minDist = d;
              bestColor = cell.color;
              bestAngle = (cell.angle * Math.PI) / 180;
            }
          });
        }

        // Feature color override for edge precision
        if (stage === PaintingStage.SUBJECT_DETAIL && features.length > 0) {
           features.forEach((f: any) => {
              if (Math.abs(x - f.x) < 0.02 && Math.abs(y - f.y) < 0.02) {
                 if (Math.random() > 0.5) bestColor = f.color;
              }
           });
        }

        if (stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
            const details = focalPoint.detailColors || ['#ffffff'];
            if (Math.random() > 0.3) bestColor = details[Math.floor(Math.random() * details.length)];
        }

        let length, width, angleOffset;
        switch(stage) {
          case PaintingStage.BACKGROUND_WASH:
            length = 0.15 + Math.random() * 0.25;
            width = 80 + Math.random() * 60;
            angleOffset = (Math.random() - 0.5) * 1.8;
            break;
          case PaintingStage.MIDGROUND_FORMS:
            length = 0.03 + Math.random() * 0.07;
            width = 15 + Math.random() * 20;
            angleOffset = (Math.random() - 0.5) * 0.5;
            break;
          case PaintingStage.SUBJECT_DETAIL:
            length = 0.004 + Math.random() * 0.012; 
            width = 2.0 + Math.random() * 4.5;
            angleOffset = (Math.random() - 0.5) * 0.15; // Strict edge following
            break;
          case PaintingStage.HIGHTLIGHT_IMPASTO:
            length = 0.002 + Math.random() * 0.008;
            width = 1.0 + Math.random() * 3.5;
            angleOffset = (Math.random() - 0.5) * 0.2;
            break;
          default:
            length = 0.05; width = 10; angleOffset = 0;
        }

        strokes.push({
          x, y, length, width, color: bestColor,
          angle: bestAngle + angleOffset,
          opacity: stage === PaintingStage.BACKGROUND_WASH ? 0.4 : 0.98,
          pressure: 0.3 + Math.random() * 0.7,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = canvas.width;
    const h = canvas.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    // Physical oil bristle simulation
    const passes = stroke.stage === PaintingStage.BACKGROUND_WASH ? 1 : 2;
    for(let p = 0; p < passes; p++) {
        const bristles = Math.max(1, Math.floor(stroke.width / 1.7));
        for (let j = 0; j < bristles; j++) {
            const offset = (j - bristles / 2) * 1.1;
            const noise = (Math.random() - 0.5) * 1.0;

            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity * (0.3 + Math.random() * 0.7);
            ctx.lineWidth = 0.4 + Math.random() * 1.2;
            ctx.lineCap = 'round';

            ctx.moveTo(startX + offset + noise, startY + offset + noise);
            ctx.lineTo(endX + offset + noise, endY + offset + noise);
            ctx.stroke();
        }
    }

    // Edge relief (Impasto effect)
    if (stroke.width > 2.5) {
        ctx.beginPath();
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 0.3;
        ctx.moveTo(startX + 0.3, startY + 0.3);
        ctx.lineTo(endX + 0.3, endY + 0.3);
        ctx.stroke();

        ctx.beginPath();
        ctx.strokeStyle = 'rgba(255,255,255,0.15)';
        ctx.lineWidth = 0.3;
        ctx.moveTo(startX - 0.3, startY - 0.3);
        ctx.lineTo(endX - 0.3, endY - 0.3);
        ctx.stroke();
    }

    ctx.restore();

    const soundThreshold = stroke.stage === PaintingStage.BACKGROUND_WASH ? 0.65 : 0.97;
    if (Math.random() > soundThreshold || stroke.width > 50) {
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, 0.05 + stroke.length * 0.3);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const batchSize = simState.currentStage === PaintingStage.BACKGROUND_WASH ? 80 : 
                      simState.currentStage === PaintingStage.MIDGROUND_FORMS ? 45 : 25;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);

      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 font-sans selection:bg-amber-500/30">
      <header className="px-8 py-5 border-b border-white/5 flex justify-between items-center bg-[#0a0a0a] z-30 sticky top-0 shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-gradient-to-tr from-amber-700 to-amber-500 rounded-xl flex items-center justify-center shadow-lg transform -rotate-2 hover:rotate-0 transition-all duration-500">
            <i className="fas fa-palette text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic">V-STUDIO <span className="text-amber-500">ULTRA</span></h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.4em] font-bold">Edge-Aligned Physical Render</p>
          </div>
        </div>

        <div className="flex items-center gap-10">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-white hover:bg-amber-500 text-black px-12 py-4 rounded-lg cursor-pointer transition-all duration-300 font-black text-sm tracking-widest flex items-center gap-4 shadow-[0_0_30px_rgba(255,255,255,0.1)] hover:shadow-amber-500/20">
              <i className="fas fa-upload group-hover:-translate-y-1 transition-transform"></i>
              UPLOAD SOURCE
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end w-80">
              <div className="flex justify-between w-full mb-3">
                <span className="text-[10px] text-amber-500 font-black tracking-[0.25em] uppercase animate-pulse">
                  {simState.currentStage.replace('_', ' ')}
                </span>
                <span className="text-[10px] text-zinc-400 font-mono font-bold tracking-tighter">{Math.floor(simState.progress)}% COMPLETED</span>
              </div>
              <div className="w-full h-1.5 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-500 ease-out shadow-[0_0_20px_rgba(245,158,11,1)]"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center bg-[#070707] p-6 lg:p-14 overflow-hidden">
        {/* Cinematic Backdrop */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)] opacity-50"></div>

        <div className="relative shadow-[0_100px_200px_-50px_rgba(0,0,0,0.95)] border-[24px] border-[#0f0f0f] rounded-sm overflow-hidden bg-[#151515] transition-transform duration-700 hover:scale-[1.01]">
           <canvas 
            ref={canvasRef} 
