          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/95 backdrop-blur-3xl z-40">
              <div className="flex gap-2 mb-10">
                {[...Array(6)].map((_,i) => (
                  <div key={i} className="w-2 h-8 bg-amber-500 animate-[bounce_1.2s_infinite]" style={{animationDelay: `${i*0.15}s`}}></div>
                ))}
