import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Resizes a base64 image to a maximum dimension to ensure 
 * the payload fits within API limits and prevents XHR errors.
 */
async function resizeImage(base64Str: string, maxDim: number = 512): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > height) {
        if (width > maxDim) {
          height *= maxDim / width;
          width = maxDim;
        }
      } else {
        if (height > maxDim) {
          width *= maxDim / height;
          height = maxDim;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(img, 0, 0, width, height);
      resolve(canvas.toDataURL('image/jpeg', 0.8).split(',')[1]);
    };
    img.src = `data:image/jpeg;base64,${base64Str}`;
  });
}

export async function analyzeAndPlanPainting(imageBuffer: string) {
  // Downsample to prevent "Rpc failed due to xhr error" (Error code 6)
  const optimizedImage = await resizeImage(imageBuffer, 512);

  const prompt = `
    Deep artistic decomposition for oil painting.

    1. 20x20 COLOR GRID (400 points):
       Cover (0,0) to (1,1). Return {x, y, color, angle (0-360)}.

    2. 150 DETAIL FEATURES:
       Map high-contrast edges/boundaries. Return {x, y, color}.

    3. FOCAL POINT:
       Visual center {x, y, detailColors[]}.

    Return valid JSON only. Avoid text summaries.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: optimizedImage, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER },
              detailColors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["x", "y", "detailColors"]
          },
          features: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING }
              },
              required: ["x", "y", "color"]
            }
          },
          colorGrid: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING },
                angle: { type: Type.NUMBER }
              },
              required: ["x", "y", "color", "angle"]
            }
          }
        },
        required: ["palette", "focalPoint", "colorGrid", "features"]
      }
    }
  });

  return JSON.parse(response.text);
}

