    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Source image too complex or analysis failed. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.10 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.20 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.60 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const colorGrid = analysis.colorGrid;
    const features = analysis.features || [];
    const focalPoint = analysis.focalPoint;

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);
      for (let i = 0; i < stageCount; i++) {
        let x, y;

        if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
           if (features.length > 0 && Math.random() < 0.5) {
              const f = features[Math.floor(Math.random() * features.length)];
              x = f.x + (Math.random() - 0.5) * 0.01;
              y = f.y + (Math.random() - 0.5) * 0.01;
           } else {
              if (Math.random() < 0.4) {
                 x = focalPoint.x + (Math.random() - 0.5) * 0.5;
                 y = focalPoint.y + (Math.random() - 0.5) * 0.5;
              } else {
                 x = Math.random();
                 y = Math.random();
              }
           }
        } else {
           x = Math.random();
           y = Math.random();
        }

        x = Math.max(0, Math.min(1, x));
        y = Math.max(0, Math.min(1, y));

        let bestColor = "#000000";
        let bestAngle = Math.random() * Math.PI * 2;
        let minDist = Infinity;

        for (let cell of colorGrid) {
            const d = (x - cell.x) * (x - cell.x) + (y - cell.y) * (y - cell.y);
            if (d < minDist) {
                minDist = d;
                bestColor = cell.color;
                bestAngle = (cell.angle * Math.PI) / 180;
            }
        }

        if (stage === PaintingStage.SUBJECT_DETAIL) {
           for (let f of features) {
              const d = Math.sqrt((x - f.x) * (x - f.x) + (y - f.y) * (y - f.y));
              if (d < 0.008) {
                 bestColor = f.color;
                 break;
              }
           }
        }

        if (stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
            const dToFocus = Math.sqrt((x - focalPoint.x) * (x - focalPoint.x) + (y - focalPoint.y) * (y - focalPoint.y));
            if (dToFocus < 0.3 && Math.random() > 0.5) {
              bestColor = focalPoint.detailColors[Math.floor(Math.random() * focalPoint.detailColors.length)];
            }
        }

        let length, width, angleOffset;
        switch(stage) {
          case PaintingStage.BACKGROUND_WASH:
            length = 0.2 + Math.random() * 0.4;
            width = 100 + Math.random() * 150;
            angleOffset = (Math.random() - 0.5) * 2;
            break;
          case PaintingStage.MIDGROUND_FORMS:
            length = 0.05 + Math.random() * 0.1;
            width = 30 + Math.random() * 50;
            angleOffset = (Math.random() - 0.5) * 0.5;
            break;
          case PaintingStage.SUBJECT_DETAIL:
            length = 0.002 + Math.random() * 0.008; 
            width = 1.0 + Math.random() * 3.5;
            angleOffset = (Math.random() - 0.5) * 0.1; 
            break;
          case PaintingStage.HIGHTLIGHT_IMPASTO:
            length = 0.001 + Math.random() * 0.004;
            width = 0.8 + Math.random() * 2.5;
            angleOffset = (Math.random() - 0.5) * 0.2;
            break;
          default:
            length = 0.05; width = 10; angleOffset = 0;
        }

        strokes.push({
          x, y, length, width, color: bestColor,
          angle: bestAngle + angleOffset,
          opacity: stage === PaintingStage.BACKGROUND_WASH ? 0.3 : 0.98,
          pressure: 0.2 + Math.random() * 0.8,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = canvas.width;
    const h = canvas.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();
    const passes = stroke.stage === PaintingStage.BACKGROUND_WASH ? 1 : 2;
    for(let p = 0; p < passes; p++) {
        const bristles = Math.max(1, Math.floor(stroke.width / 1.5));
        for (let j = 0; j < bristles; j++) {
            const offset = (j - bristles / 2) * 1.05;
            const noise = (Math.random() - 0.5) * 0.7;
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity * (0.35 + Math.random() * 0.65);
            ctx.lineWidth = 0.4 + Math.random() * 0.8;
            ctx.lineCap = 'round';
            ctx.moveTo(startX + offset + noise, startY + offset + noise);
            ctx.lineTo(endX + offset + noise, endY + offset + noise);
            ctx.stroke();
        }
    }
    if (stroke.width > 2.0 && stroke.stage !== PaintingStage.BACKGROUND_WASH) {
        ctx.lineWidth = 0.15;
        ctx.beginPath();
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.moveTo(startX + 0.5, startY + 0.5);
        ctx.lineTo(endX + 0.5, endY + 0.5);
        ctx.stroke();
        ctx.beginPath();
        ctx.strokeStyle = 'rgba(255,255,255,0.15)';
        ctx.moveTo(startX - 0.5, startY - 0.5);
        ctx.lineTo(endX - 0.5, endY - 0.5);
        ctx.stroke();
    }
    ctx.restore();

    if (Math.random() > 0.992 || stroke.width > 120) {
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, 0.05 + stroke.length * 0.5);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const batchSize = simState.currentStage === PaintingStage.BACKGROUND_WASH ? 180 : 
                      simState.currentStage === PaintingStage.MIDGROUND_FORMS ? 90 : 55;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);
      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 font-sans selection:bg-amber-500/30">
      <header className="px-8 py-5 border-b border-white/5 flex justify-between items-center bg-[#0a0a0a] z-30 sticky top-0 shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-gradient-to-tr from-amber-700 to-amber-500 rounded-xl flex items-center justify-center shadow-lg transform -rotate-2 hover:rotate-0 transition-all duration-500">
            <i className="fas fa-palette text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic">V-STUDIO <span className="text-amber-500 uppercase tracking-widest text-xs ml-2 not-italic">Hyper-Fidelity</span></h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.4em] font-bold">400-Point Optical Neural Mapping</p>
          </div>
        </div>

        <div className="flex items-center gap-10">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-zinc-100 hover:bg-amber-500 text-black px-12 py-4 rounded-lg cursor-pointer transition-all duration-300 font-black text-sm tracking-widest flex items-center gap-4 shadow-[0_0_30px_rgba(255,255,255,0.05)]">
              <i className="fas fa-camera-retro group-hover:-rotate-12 transition-transform"></i>
              REPAINT IMAGE
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end w-80">
              <div className="flex justify-between w-full mb-3">
                <span className="text-[10px] text-amber-500 font-black tracking-[0.3em] uppercase animate-pulse">
                  {simState.currentStage.replace('_', ' ')}
                </span>
                <span className="text-[10px] text-zinc-400 font-mono font-bold tracking-tighter">{Math.floor(simState.progress)}%</span>
              </div>
              <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-500 ease-out shadow-[0_0_20px_rgba(245,158,11,1)]"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center bg-[#070707] p-6 lg:p-14 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_#151515_0%,_#050505_100%)] opacity-80"></div>

        {/* Floating Reference Window */}
        {image && showReference && (
          <div className="absolute top-10 right-10 w-64 aspect-video bg-[#0c0c0c] border border-white/10 rounded-lg shadow-2xl z-50 overflow-hidden transition-all duration-500 group">
            <div className="bg-[#121212] px-3 py-1 flex items-center justify-between border-b border-white/5">
              <span className="text-[8px] font-black tracking-widest text-zinc-400 uppercase">Reference Window</span>
              <button onClick={() => setShowReference(false)} className="text-zinc-600 hover:text-white transition-colors">
                <i className="fas fa-times text-[10px]"></i>
              </button>
            </div>
            <img src={image} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" alt="Source Reference" />
          </div>
        )}

        <div className="relative shadow-[0_120px_240px_-60px_rgba(0,0,0,1)] border-[30px] border-[#0c0c0c] rounded-sm overflow-hidden bg-[#111] transition-transform duration-1000">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[70vh] block object-contain"
          />

          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#080808] p-20 text-center">
              <div className="w-48 h-48 mb-10 relative group">
                 <div className="absolute inset-0 bg-amber-500/5 rounded-full animate-ping blur-2xl"></div>
                 <div className="relative w-full h-full rounded-full border border-white/5 flex items-center justify-center group-hover:border-amber-500/20 transition-all duration-700">
                  <i className="fas fa-layer-group text-6xl opacity-5 group-hover:opacity-20 transition-opacity"></i>
                 </div>
              </div>
              <h2 className="text-4xl font-black text-white mb-6 tracking-tighter uppercase italic">Empty Canvas</h2>
              <p className="max-w-lg text-xs leading-loose text-zinc-500 font-bold uppercase tracking-[0.5em] opacity-60">
                Awaiting Optical Source Decomposition. <br/>
                75,000 Precision Bristle Tracks Ready.
              </p>
            </div>
          )}

          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/98 backdrop-blur-3xl z-40">
              <div className="relative w-24 h-24 mb-12">
                <div className="absolute inset-0 border-2 border-amber-500/20 rounded-full"></div>
                <div className="absolute inset-0 border-t-2 border-amber-500 rounded-full animate-spin"></div>
              </div>
              <p className="text-amber-500 font-black tracking-[0.8em] text-xs uppercase animate-pulse">
                Neural Sampling (400 Nodes)
              </p>
              <p className="mt-4 text-zinc-600 text-[10px] uppercase tracking-[0.4em] font-black">Deconstructing Chromatic Tensors...</p>
            </div>
          )}
        </div>

        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-10 px-12 py-6 bg-[#0a0a0a]/95 border border-white/5 rounded-3xl shadow-3xl backdrop-blur-2xl">
          <button onClick={() => asmrService.resume()} className="group flex items-center gap-5 text-[10px] font-black tracking-[0.3em] uppercase text-amber-500 hover:text-white transition-all">
            <i className="fas fa-headphones text-2xl group-hover:scale-125 transition-transform"></i> AUDITORY IMMERSION
          </button>
          {!showReference && image && (
            <>
              <div className="w-px h-10 bg-white/5"></div>
              <button onClick={() => setShowReference(true)} className="text-[10px] font-black tracking-[0.3em] uppercase text-zinc-400 hover:text-amber-500 transition-all">
                Show Reference
              </button>
            </>
          )}
          <div className="w-px h-10 bg-white/5"></div>
          <div className="text-[10px] font-black tracking-[0.3em] uppercase text-zinc-500 flex items-center gap-4">
            <span className="w-3 h-3 rounded-full bg-zinc-900 border border-white/10"></span>
            {simState.isPainting ? `Rendering structural detail` : `Ready`}
          </div>
        </div>
      </main>

      <footer className="h-16 bg-[#030303] border-t border-white/5 flex items-center px-10 justify-between text-[10px] text-zinc-600 uppercase tracking-[0.4em] font-black">
        <div className="flex gap-20">
          <div className="flex items-center gap-4">
            <span className="w-2 h-2 rounded-full bg-amber-600 animate-pulse"></span>
            <span>400 Spatial Sampling Nodes</span>
          </div>
          <div className="flex items-center gap-4">
            <i className="fas fa-dna opacity-20"></i>
            <span>Edge-Flow Tensor Synthesis</span>
          </div>
        </div>
        <div className="flex gap-10 items-center">
          {simState.isPainting && (
            <div className="flex items-center gap-6">
              <span className="text-zinc-500">Buffer: {simState.renderedStrokes.toLocaleString()} / {STROKE_COUNT.toLocaleString()}</span>
              <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span>
            </div>
          )}
          <span className="bg-[#080808] px-6 py-2 rounded-lg border border-white/5 text-zinc-500 shadow-inner tracking-[0.6em] font-black">720p MASTER</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Stroke {
  x: number;
  y: number;
  length: number;
  angle: number;
  width: number;
  color: string;
  opacity: number;
  pressure: number;
  stage: PaintingStage;
}

export enum PaintingStage {
  UNDERPAINTING_STRICT = 'UNDERPAINTING_STRICT',
  BACKGROUND_WASH = 'BACKGROUND_WASH',
  MIDGROUND_FORMS = 'MIDGROUND_FORMS',
  SUBJECT_DETAIL = 'SUBJECT_DETAIL',
  HIGHTLIGHT_IMPASTO = 'HIGHTLIGHT_IMPASTO'
}

export interface SimulationState {
  isPainting: boolean;
  progress: number;
  currentStage: PaintingStage;
  totalStrokes: number;
  renderedStrokes: number;
}

import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const STROKE_COUNT = 85000; 

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showReference, setShowReference] = useState(true);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.UNDERPAINTING_STRICT,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const fullBase64 = event.target?.result as string;
      const dataOnly = fullBase64.split(',')[1];
      setImage(fullBase64);
      startSimulation(dataOnly);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      if (!analysis || !analysis.colorGrid || analysis.colorGrid.length < 100) {
        throw new Error("Analysis failed to capture enough spatial data.");
      }

      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length,
        currentStage: PaintingStage.UNDERPAINTING_STRICT
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#b8b2a3'; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          // Priming
          ctx.globalAlpha = 0.08;
          ctx.fillStyle = '#000';
          for(let i=0; i<canvas.width; i+=4) ctx.fillRect(i, 0, 1, canvas.height);
          for(let i=0; i<canvas.height; i+=4) ctx.fillRect(0, i, canvas.width, 1);
          ctx.globalAlpha = 1.0;
        }
      }
    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Source image too complex. Analysis failed.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.UNDERPAINTING_STRICT, ratio: 0.15 },
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.10 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.20 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.45 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const colorGrid = analysis.colorGrid;
    const features = analysis.features || [];
    const focalPoint = analysis.focalPoint;

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);

      // For UNDERPAINTING, we iterate linearly across the grid to ensure structure
      if (stage === PaintingStage.UNDERPAINTING_STRICT) {
        const gridCount = colorGrid.length;
        const subCount = Math.ceil(stageCount / gridCount);
        for (let cell of colorGrid) {
            for (let j = 0; j < subCount; j++) {
                strokes.push({
                    x: cell.x + (Math.random() - 0.5) * 0.05,
                    y: cell.y + (Math.random() - 0.5) * 0.05,
                    length: 0.1 + Math.random() * 0.1,
                    width: 40 + Math.random() * 40,
                    color: cell.color,
                    angle: (cell.angle * Math.PI) / 180,
                    opacity: 0.4,
                    pressure: 0.5,
                    stage
                });
            }
        }
        return;
      }

      for (let i = 0; i < stageCount; i++) {
        let x, y;

        if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
           if (features.length > 0 && Math.random() < 0.6) {
              const f = features[Math.floor(Math.random() * features.length)];
              x = f.x + (Math.random() - 0.5) * 0.01;
              y = f.y + (Math.random() - 0.5) * 0.01;
           } else {
              x = Math.random();
              y = Math.random();
           }
        } else {
           x = Math.random();
           y = Math.random();
        }

        x = Math.max(0, Math.min(1, x));
        y = Math.max(0, Math.min(1, y));

        let bestColor = "#000000";
        let bestAngle = Math.random() * Math.PI * 2;
        let minDist = Infinity;

        for (let cell of colorGrid) {
            const d = (x - cell.x) * (x - cell.x) + (y - cell.y) * (y - cell.y);
            if (d < minDist) {
                minDist = d;
                bestColor = cell.color;
                bestAngle = (cell.angle * Math.PI) / 180;
            }
        }

        if (stage === PaintingStage.SUBJECT_DETAIL) {
           for (let f of features) {
              const d = Math.sqrt((x - f.x) * (x - f.x) + (y - f.y) * (y - f.y));
              if (d < 0.006) {
                 bestColor = f.color;
                 break;
              }
           }
        }

        let length, width, angleOffset, opacity;
        switch(stage) {
          case PaintingStage.BACKGROUND_WASH:
            length = 0.15 + Math.random() * 0.3;
            width = 80 + Math.random() * 100;
            angleOffset = (Math.random() - 0.5) * 1.5;
            opacity = 0.3;
            break;
          case PaintingStage.MIDGROUND_FORMS:
            length = 0.04 + Math.random() * 0.08;
            width = 25 + Math.random() * 45;
            angleOffset = (Math.random() - 0.5) * 0.4;
            opacity = 0.8;
            break;
          case PaintingStage.SUBJECT_DETAIL:
            length = 0.003 + Math.random() * 0.012; 
            width = 1.2 + Math.random() * 4.0;
            angleOffset = (Math.random() - 0.5) * 0.1;
            opacity = 0.95;
            break;
          case PaintingStage.HIGHTLIGHT_IMPASTO:
            length = 0.002 + Math.random() * 0.006;
            width = 0.8 + Math.random() * 3.0;
            angleOffset = (Math.random() - 0.5) * 0.2;
            opacity = 1.0;
            break;
          default:
            length = 0.05; width = 10; angleOffset = 0; opacity = 1.0;
        }

        strokes.push({
          x, y, length, width, color: bestColor,
          angle: bestAngle + angleOffset,
          opacity: opacity,
          pressure: 0.3 + Math.random() * 0.7,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = canvas.width;
    const h = canvas.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    // In Underpainting, we use flat broad strokes for structural accuracy
    if (stroke.stage === PaintingStage.UNDERPAINTING_STRICT) {
        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.globalAlpha = stroke.opacity;
        ctx.lineWidth = stroke.width;
        ctx.lineCap = 'butt';
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.stroke();
    } else {
        const passes = stroke.stage === PaintingStage.BACKGROUND_WASH ? 1 : 2;
        for(let p = 0; p < passes; p++) {
            const bristles = Math.max(1, Math.floor(stroke.width / 1.5));
            for (let j = 0; j < bristles; j++) {
                const offset = (j - bristles / 2) * 1.05;
                const noise = (Math.random() - 0.5) * 0.7;
                ctx.beginPath();
                ctx.strokeStyle = stroke.color;
                ctx.globalAlpha = stroke.opacity * (0.4 + Math.random() * 0.6);
                ctx.lineWidth = 0.5 + Math.random() * 1.0;
                ctx.lineCap = 'round';
                ctx.moveTo(startX + offset + noise, startY + offset + noise);
                ctx.lineTo(endX + offset + noise, endY + offset + noise);
                ctx.stroke();
            }
        }

        // Tactile depth
        if (stroke.width > 2.0 && stroke.stage !== PaintingStage.BACKGROUND_WASH) {
            ctx.lineWidth = 0.2;
            ctx.strokeStyle = 'rgba(0,0,0,0.12)';
            ctx.beginPath();
            ctx.moveTo(startX + 0.5, startY + 0.5);
            ctx.lineTo(endX + 0.5, endY + 0.5);
            ctx.stroke();
            ctx.strokeStyle = 'rgba(255,255,255,0.15)';
            ctx.beginPath();
            ctx.moveTo(startX - 0.5, startY - 0.5);
            ctx.lineTo(endX - 0.5, endY - 0.5);
            ctx.stroke();
        }
    }

    ctx.restore();

    if (Math.random() > 0.995 || stroke.width > 120) {
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, 0.05 + stroke.length * 0.5);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const batchSize = simState.currentStage === PaintingStage.UNDERPAINTING_STRICT ? 250 :
                      simState.currentStage === PaintingStage.BACKGROUND_WASH ? 150 : 
                      simState.currentStage === PaintingStage.MIDGROUND_FORMS ? 80 : 45;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);
      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 font-sans selection:bg-amber-500/30">
      <header className="px-8 py-5 border-b border-white/5 flex justify-between items-center bg-[#0a0a0a] z-30 sticky top-0 shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-gradient-to-tr from-amber-700 to-amber-500 rounded-xl flex items-center justify-center shadow-lg transform -rotate-2 hover:rotate-0 transition-all duration-500">
            <i className="fas fa-paint-brush text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic">V-STUDIO <span className="text-amber-500 uppercase tracking-widest text-xs ml-2 not-italic">Engine v5.2</span></h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.4em] font-bold">Structural Fidelity Override Active</p>
          </div>
        </div>

        <div className="flex items-center gap-10">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-zinc-100 hover:bg-amber-500 text-black px-12 py-4 rounded-lg cursor-pointer transition-all duration-300 font-black text-sm tracking-widest flex items-center gap-4 shadow-[0_0_30px_rgba(255,255,255,0.05)]">
              <i className="fas fa-file-image group-hover:scale-110 transition-transform"></i>
              SIMULATE PAINTING
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end w-80">
              <div className="flex justify-between w-full mb-3">
                <span className="text-[10px] text-amber-500 font-black tracking-[0.3em] uppercase animate-pulse">
                  {simState.currentStage.replace('_', ' ')}
                </span>
                <span className="text-[10px] text-zinc-400 font-mono font-bold tracking-tighter">{Math.floor(simState.progress)}%</span>
              </div>
              <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-500 ease-out"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center bg-[#070707] p-6 lg:p-14 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_#1a1a1a_0%,_#050505_100%)] opacity-80"></div>

        {image && showReference && (
          <div className="absolute top-10 right-10 w-72 aspect-video bg-[#0c0c0c] border border-white/10 rounded-xl shadow-2xl z-50 overflow-hidden group">
            <div className="bg-[#121212] px-4 py-2 flex items-center justify-between border-b border-white/5">
              <span className="text-[9px] font-black tracking-widest text-zinc-500 uppercase">Original Reference</span>
              <button onClick={() => setShowReference(false)} className="text-zinc-600 hover:text-white transition-colors">
                <i className="fas fa-times text-xs"></i>
              </button>
            </div>
            <img src={image} className="w-full h-full object-cover opacity-90" alt="Source Reference" />
          </div>
        )}

        <div className="relative shadow-[0_150px_300px_-80px_rgba(0,0,0,1)] border-[32px] border-[#0e0e0e] rounded-sm overflow-hidden bg-[#111] transition-all duration-1000">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[65vh] block object-contain"
          />

          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#080808] p-20 text-center">
              <i className="fas fa-cloud-upload-alt text-7xl opacity-5 mb-10"></i>
              <h2 className="text-4xl font-black text-white mb-6 tracking-tighter uppercase italic">Waiting for Render Command</h2>
              <p className="max-w-lg text-[10px] leading-loose text-zinc-600 font-bold uppercase tracking-[0.5em] opacity-80">
                Awaiting Optical Decomposition...
              </p>
            </div>
          )}

          {isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/98 backdrop-blur-3xl z-40">
              <div className="relative w-28 h-28 mb-12">
                <div className="absolute inset-0 border-2 border-amber-500/10 rounded-full"></div>
                <div className="absolute inset-0 border-t-2 border-amber-500 rounded-full animate-spin"></div>
              </div>
              <p className="text-amber-500 font-black tracking-[0.8em] text-xs uppercase animate-pulse">
                Analyzing Structure (400 Nodes)
              </p>
            </div>
          )}
        </div>

        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-10 px-12 py-6 bg-[#0a0a0a]/95 border border-white/5 rounded-3xl shadow-3xl backdrop-blur-2xl">
          <button onClick={() => asmrService.resume()} className="group flex items-center gap-5 text-[10px] font-black tracking-[0.3em] uppercase text-amber-500 hover:text-white transition-all">
            <i className="fas fa-volume-up text-2xl"></i> SOUNDSCAPE
          </button>
          {!showReference && image && (
            <>
              <div className="w-px h-10 bg-white/5"></div>
              <button onClick={() => setShowReference(true)} className="text-[10px] font-black tracking-[0.3em] uppercase text-zinc-500 hover:text-amber-500 transition-all">
                Show Ref
              </button>
            </>
          )}
          <div className="w-px h-10 bg-white/5"></div>
          <div className="text-[10px] font-black tracking-[0.3em] uppercase text-zinc-600 flex items-center gap-4">
            {simState.isPainting ? `Rendering Layers...` : `System Ready`}
          </div>
        </div>
      </main>

      <footer className="h-16 bg-[#030303] border-t border-white/5 flex items-center px-10 justify-between text-[10px] text-zinc-700 uppercase tracking-[0.4em] font-black">
        <div className="flex gap-20">
          <span>Structural Mode: Strict</span>
          <span>Buffer: {simState.renderedStrokes.toLocaleString()} Tracks</span>
        </div>
        <div className="flex gap-10 items-center">
          <span className="bg-[#080808] px-6 py-2 rounded-lg border border-white/5 text-zinc-600 shadow-inner">PROCEDURAL RENDER</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Stroke {
  x: number;
  y: number;
  length: number;
  angle: number;
  width: number;
  color: string;
  opacity: number;
  pressure: number;
  stage: PaintingStage;
}

export enum PaintingStage {
  UNDERPAINTING_STRICT = 'UNDERPAINTING_STRICT',
  FORM_CLARIFICATION = 'FORM_CLARIFICATION',
  BACKGROUND_WASH = 'BACKGROUND_WASH',
  MIDGROUND_FORMS = 'MIDGROUND_FORMS',
  SUBJECT_DETAIL = 'SUBJECT_DETAIL',
  HIGHTLIGHT_IMPASTO = 'HIGHTLIGHT_IMPASTO'
}

export interface SimulationState {
  isPainting: boolean;
  progress: number;
  currentStage: PaintingStage;
  totalStrokes: number;
  renderedStrokes: number;
}

import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState } from './types';

const STROKE_COUNT = 95000; 

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showReference, setShowReference] = useState(true);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.UNDERPAINTING_STRICT,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const fullBase64 = event.target?.result as string;
      const dataOnly = fullBase64.split(',')[1];
      setImage(fullBase64);
      startSimulation(dataOnly);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      if (!analysis || !analysis.colorGrid || analysis.colorGrid.length < 100) {
        throw new Error("Analysis failed to capture enough spatial data.");
      }

      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length,
        currentStage: PaintingStage.UNDERPAINTING_STRICT
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#a8a293'; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.globalAlpha = 0.1;
          ctx.fillStyle = '#000';
          for(let i=0; i<canvas.width; i+=5) ctx.fillRect(i, 0, 1, canvas.height);
          for(let i=0; i<canvas.height; i+=5) ctx.fillRect(0, i, canvas.width, 1);
          ctx.globalAlpha = 1.0;
        }
      }
    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Source image deconstruction error.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.UNDERPAINTING_STRICT, ratio: 0.12 },
      { stage: PaintingStage.FORM_CLARIFICATION, ratio: 0.18 },
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.08 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.17 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.35 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const colorGrid = analysis.colorGrid;
    const features = analysis.features || [];
    const focalPoint = analysis.focalPoint;

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);

      if (stage === PaintingStage.UNDERPAINTING_STRICT) {
        const gridCount = colorGrid.length;
        const subCount = Math.ceil(stageCount / gridCount);
        for (let cell of colorGrid) {
            for (let j = 0; j < subCount; j++) {
                strokes.push({
                    x: cell.x + (Math.random() - 0.5) * 0.03,
                    y: cell.y + (Math.random() - 0.5) * 0.03,
                    length: 0.15,
                    width: 60,
                    color: cell.color,
                    angle: (cell.angle * Math.PI) / 180,
                    opacity: 0.45,
                    pressure: 0.4,
                    stage
                });
            }
        }
        return;
      }

      if (stage === PaintingStage.FORM_CLARIFICATION) {
        // High density reinforcement pass
        for (let i = 0; i < stageCount; i++) {
          const x = Math.random();
          const y = Math.random();
          let bestCell = colorGrid[0];
          let minDist = Infinity;
          for (let cell of colorGrid) {
              const d = (x - cell.x)**2 + (y - cell.y)**2;
              if (d < minDist) { minDist = d; bestCell = cell; }
          }
          strokes.push({
              x, y,
              length: 0.03 + Math.random() * 0.03,
              width: 15 + Math.random() * 15,
              color: bestCell.color,
              angle: (bestCell.angle * Math.PI) / 180, // Follows surface flow
              opacity: 0.85,
              pressure: 0.7,
              stage
          });
        }
        return;
      }

      for (let i = 0; i < stageCount; i++) {
        let x = Math.random();
        let y = Math.random();

        if ((stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) && features.length > 0) {
           if (Math.random() < 0.65) {
              const f = features[Math.floor(Math.random() * features.length)];
              x = f.x + (Math.random() - 0.5) * 0.008;
              y = f.y + (Math.random() - 0.5) * 0.008;
           }
        }

        let bestColor = "#000";
        let bestAngle = Math.random() * Math.PI * 2;
        let minDist = Infinity;
        for (let cell of colorGrid) {
            const d = (x - cell.x)**2 + (y - cell.y)**2;
            if (d < minDist) {
                minDist = d;
                bestColor = cell.color;
                bestAngle = (cell.angle * Math.PI) / 180;
            }
        }

        let length, width, angleOffset, opacity;
        switch(stage) {
          case PaintingStage.BACKGROUND_WASH:
            length = 0.2; width = 120; angleOffset = (Math.random()-0.5); opacity = 0.25; break;
          case PaintingStage.MIDGROUND_FORMS:
            length = 0.06; width = 35; angleOffset = (Math.random()-0.5)*0.3; opacity = 0.75; break;
          case PaintingStage.SUBJECT_DETAIL:
            length = 0.008; width = 2.5; angleOffset = (Math.random()-0.5)*0.05; opacity = 0.98; break;
          case PaintingStage.HIGHTLIGHT_IMPASTO:
            length = 0.003; width = 1.5; angleOffset = 0; opacity = 1.0; break;
          default:
            length = 0.05; width = 10; angleOffset = 0; opacity = 1.0;
        }

        strokes.push({
          x, y, length, width, color: bestColor,
          angle: bestAngle + angleOffset,
          opacity: opacity,
          pressure: 0.4 + Math.random() * 0.6,
          stage
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = canvas.width;
    const h = canvas.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    if (stroke.stage === PaintingStage.UNDERPAINTING_STRICT || stroke.stage === PaintingStage.FORM_CLARIFICATION) {
        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.globalAlpha = stroke.opacity;
        ctx.lineWidth = stroke.width;
        ctx.lineCap = stroke.stage === PaintingStage.UNDERPAINTING_STRICT ? 'butt' : 'round';
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.stroke();
    } else {
        const bristles = Math.max(1, Math.floor(stroke.width / 1.2));
        for (let j = 0; j < bristles; j++) {
            const offset = (j - bristles / 2) * 1.02;
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity * (0.4 + Math.random() * 0.5);
            ctx.lineWidth = 0.6;
            ctx.moveTo(startX + offset, startY + offset);
            ctx.lineTo(endX + offset, endY + offset);
            ctx.stroke();
        }
    }

    ctx.restore();

    if (Math.random() > 0.994 || stroke.width > 50) {
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, 0.1 + stroke.length * 0.4);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const speeds = {
      [PaintingStage.UNDERPAINTING_STRICT]: 300,
      [PaintingStage.FORM_CLARIFICATION]: 220,
      [PaintingStage.BACKGROUND_WASH]: 180,
      [PaintingStage.MIDGROUND_FORMS]: 90,
      [PaintingStage.SUBJECT_DETAIL]: 55,
      [PaintingStage.HIGHTLIGHT_IMPASTO]: 35
    };

    const batchSize = speeds[simState.currentStage] || 50;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);
      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 font-sans selection:bg-amber-500/30">
      <header className="px-8 py-5 border-b border-white/5 flex justify-between items-center bg-[#0a0a0a] z-30 sticky top-0 shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-gradient-to-tr from-amber-700 to-amber-500 rounded-xl flex items-center justify-center shadow-lg transform -rotate-2">
            <i className="fas fa-microchip text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic">V-PAINT <span className="text-amber-500 uppercase tracking-widest text-xs ml-2 not-italic">Refined Optics</span></h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.4em] font-bold">Structural/Form Clarification Logic v2</p>
          </div>
        </div>

        <div className="flex items-center gap-10">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-zinc-100 hover:bg-amber-500 text-black px-12 py-4 rounded-lg cursor-pointer transition-all duration-300 font-black text-sm tracking-widest flex items-center gap-4 shadow-xl">
              <i className="fas fa-upload group-hover:translate-y-[-2px] transition-transform"></i>
              START RENDER
              <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
            </label>
          )}
          {simState.isPainting && (
            <div className="flex flex-col items-end w-80">
              <div className="flex justify-between w-full mb-3">
                <span className="text-[10px] text-amber-500 font-black tracking-[0.3em] uppercase animate-pulse">
                  {simState.currentStage.replace('_', ' ')}
                </span>
                <span className="text-[10px] text-zinc-400 font-mono font-bold">{Math.floor(simState.progress)}%</span>
              </div>
              <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-500"
                  style={{ width: `${simState.progress}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 relative flex items-center justify-center bg-[#070707] p-6 lg:p-14 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_#1c1c1c_0%,_#050505_100%)] opacity-80"></div>

        {image && showReference && (
          <div className="absolute top-10 right-10 w-72 aspect-video bg-[#0c0c0c] border border-white/10 rounded-xl shadow-2xl z-50 overflow-hidden group">
            <div className="bg-[#121212] px-4 py-2 flex items-center justify-between border-b border-white/5">
              <span className="text-[9px] font-black tracking-widest text-zinc-500 uppercase">Optical Source</span>
              <button onClick={() => setShowReference(false)} className="text-zinc-600 hover:text-white transition-colors">
                <i className="fas fa-times text-xs"></i>
              </button>
            </div>
            <img src={image} className="w-full h-full object-cover opacity-90" alt="Source Reference" />
          </div>
        )}

        <div className="relative shadow-[0_150px_300px_-80px_rgba(0,0,0,1)] border-[32px] border-[#111] rounded-sm overflow-hidden bg-[#111]">
           <canvas 
            ref={canvasRef} 
            width={1280} 
            height={720} 
            className="max-w-full max-h-[65vh] block object-contain shadow-inner"
          />

          {!image && !isAnalyzing && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#080808] p-20 text-center">
              <div className="mb-10 text-6xl text-zinc-800"><i className="fas fa-brush"></i></div>
              <h2 className="text-4xl font-black text-white mb-6 tracking-tighter uppercase italic">Deconstruction Pipeline</h2>
