          <div className="text-[9px] font-black tracking-[0.3em] uppercase text-zinc-700 flex flex-col gap-1">
            <span>Strokes: {simState.renderedStrokes.toLocaleString()}</span>
            <span className="text-amber-500/50">Class: {simState.currentStage}</span>
