import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Resizes a base64 image to a very small size (320px) to ensure the 
 * payload stays well within the strict ProxyUnaryCall limits.
 */
async function resizeImage(base64Str: string, maxDim: number = 320): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > height) {
        if (width > maxDim) {
          height *= maxDim / width;
          width = maxDim;
        }
      } else {
        if (height > maxDim) {
          width *= maxDim / height;
          height = maxDim;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      // Use standard interpolation for cleaner analysis
      ctx?.drawImage(img, 0, 0, width, height);
      resolve(canvas.toDataURL('image/jpeg', 0.6).split(',')[1]);
    };
    img.src = `data:image/jpeg;base64,${base64Str}`;
  });
}

export async function analyzeAndPlanPainting(imageBuffer: string) {
  // Use a smaller dimension (320px) to prevent Rpc 500/code 6 errors.
  const optimizedImage = await resizeImage(imageBuffer, 320);

  // Simplified prompt to reduce output token count and parsing complexity
  const prompt = `
    Analyze this image for an oil painting plan.
    1. Grid: 15x15 points (x, y, color, angle 0-360).
    2. 50 Edge points (x, y, color).
    3. Focal: {x, y, detailColors}.
    Return JSON only.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', // Flash is faster and less prone to gateway timeouts
    contents: [
      {
        parts: [
          { inlineData: { data: optimizedImage, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          palette: { type: Type.ARRAY, items: { type: Type.STRING } },
          focalPoint: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER },
              y: { type: Type.NUMBER },
              detailColors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["x", "y", "detailColors"]
          },
          features: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING }
              },
              required: ["x", "y", "color"]
            }
          },
          colorGrid: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                color: { type: Type.STRING },
                angle: { type: Type.NUMBER }
              },
              required: ["x", "y", "color", "angle"]
            }
          }
        },
        required: ["palette", "focalPoint", "colorGrid", "features"]
      }
    }
  });

  if (!response.text) {
    throw new Error("Empty response from AI");
  }

  return JSON.parse(response.text);
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Resizes a base64 image to a minimal size (256px) to stay safely within 
 * the tight ProxyUnaryCall payload limits and prevent XHR timeout/overflow errors.
 */
async function resizeImage(base64Str: string, maxDim: number = 256): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > height) {
        if (width > maxDim) {
          height *= maxDim / width;
          width = maxDim;
        }
      } else {
        if (height > maxDim) {
          width *= maxDim / height;
          height = maxDim;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, width, height);
      }
      // Using a lower quality JPEG to further reduce the binary size transmitted over RPC
      resolve(canvas.toDataURL('image/jpeg', 0.5).split(',')[1]);
    };
    img.src = `data:image/jpeg;base64,${base64Str}`;
  });
}

