import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Resizes a base64 image to a tiny size (192px) to guarantee the 
 * payload stays well under the ProxyUnaryCall overhead limits.
 */
async function resizeImage(base64Str: string, maxDim: number = 192): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      const scale = Math.min(maxDim / width, maxDim / height);
      width *= scale;
      height *= scale;

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.imageSmoothingEnabled = true;
        ctx.drawImage(img, 0, 0, width, height);
      }
      // Low quality (0.4) significantly reduces binary payload size
      resolve(canvas.toDataURL('image/jpeg', 0.4).split(',')[1]);
    };
    img.onerror = () => resolve("");
    img.src = `data:image/jpeg;base64,${base64Str}`;
  });
}

