import { useState, useRef, useEffect, useCallback } from 'react';
import React from 'react';
import { analyzeAndPlanPainting } from './services/geminiService';
import { asmrService } from './services/audioService';
import { PaintingStage, Stroke, SimulationState, StrokeClass } from './types';

const STROKE_COUNT = 105000; 

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showReference, setShowReference] = useState(true);
  const [simState, setSimState] = useState<SimulationState>({
    isPainting: false,
    progress: 0,
    currentStage: PaintingStage.UNDERPAINTING_STRICT,
    totalStrokes: STROKE_COUNT,
    renderedStrokes: 0,
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const simulationRef = useRef<{ strokes: Stroke[], currentIndex: number }>({ strokes: [], currentIndex: 0 });
  const requestRef = useRef<number>();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const fullBase64 = event.target?.result as string;
      const dataOnly = fullBase64.split(',')[1];
      setImage(fullBase64);
      startSimulation(dataOnly);
    };
    reader.readAsDataURL(file);
  };

  const startSimulation = async (base64: string) => {
    setIsAnalyzing(true);
    asmrService.init();

    try {
      const analysis = await analyzeAndPlanPainting(base64);
      if (!analysis || !analysis.colorGrid || analysis.colorGrid.length < 10) {
        throw new Error("Analysis data insufficient.");
      }

      const generatedStrokes = generateProceduralStrokes(analysis, STROKE_COUNT);
      simulationRef.current = { strokes: generatedStrokes, currentIndex: 0 };

      setSimState(prev => ({
        ...prev,
        isPainting: true,
        renderedStrokes: 0,
        totalStrokes: generatedStrokes.length,
        currentStage: PaintingStage.UNDERPAINTING_STRICT
      }));

      const canvas = canvasRef.current;
      if (canvas) {
        const ctx = canvas.getContext('2d', { alpha: false });
        if (ctx) {
          ctx.fillStyle = '#9c9789'; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.globalAlpha = 0.12;
          ctx.fillStyle = '#000';
          for(let i=0; i<canvas.width; i+=6) ctx.fillRect(i, 0, 1, canvas.height);
          for(let i=0; i<canvas.height; i+=6) ctx.fillRect(0, i, canvas.width, 1);
          ctx.globalAlpha = 1.0;
        }
      }
    } catch (error) {
      console.error("Simulation failed:", error);
      alert("Source image deconstruction error.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateProceduralStrokes = (analysis: any, count: number): Stroke[] => {
    const strokes: Stroke[] = [];
    const stages = [
      { stage: PaintingStage.UNDERPAINTING_STRICT, ratio: 0.15 },
      { stage: PaintingStage.FORM_CLARIFICATION, ratio: 0.20 },
      { stage: PaintingStage.BACKGROUND_WASH, ratio: 0.05 },
      { stage: PaintingStage.MIDGROUND_FORMS, ratio: 0.15 },
      { stage: PaintingStage.SUBJECT_DETAIL, ratio: 0.35 },
      { stage: PaintingStage.HIGHTLIGHT_IMPASTO, ratio: 0.10 }
    ];

    const colorGrid = analysis.colorGrid;
    const features = analysis.features || [];
    const focalPoint = analysis.focalPoint;

    stages.forEach(({ stage, ratio }) => {
      const stageCount = Math.floor(count * ratio);

      for (let i = 0; i < stageCount; i++) {
        let x = Math.random();
        let y = Math.random();

        if ((stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) && features.length > 0) {
           if (Math.random() < 0.7) {
              const f = features[Math.floor(Math.random() * features.length)];
              x = f.x + (Math.random() - 0.5) * 0.005;
              y = f.y + (Math.random() - 0.5) * 0.005;
           }
        }

        let bestCell = colorGrid[0];
        let minDist = Infinity;
        for (let cell of colorGrid) {
            const d = (x - cell.x)**2 + (y - cell.y)**2;
            if (d < minDist) { minDist = d; bestCell = cell; }
        }

        const distToFocal = Math.sqrt((x - focalPoint.x)**2 + (y - focalPoint.y)**2);
        const distToFeature = features.length > 0 
          ? features.reduce((min, f) => Math.min(min, Math.sqrt((x-f.x)**2 + (y-f.y)**2)), 1)
          : 1;

        let strokeClass: StrokeClass;
        if (stage === PaintingStage.UNDERPAINTING_STRICT) {
          strokeClass = StrokeClass.STRUCTURAL;
        } else if (distToFeature < 0.02 || stage === PaintingStage.FORM_CLARIFICATION) {
          strokeClass = StrokeClass.FORM_DEFINING;
        } else if (stage === PaintingStage.HIGHTLIGHT_IMPASTO || (distToFocal < 0.1 && Math.random() < 0.3)) {
          strokeClass = StrokeClass.ACCENT;
        } else {
          strokeClass = StrokeClass.TRANSITIONAL;
        }

        let length, width, angle, opacity, pressure;
        angle = (bestCell.angle * Math.PI) / 180 + (Math.random() - 0.5) * 0.2;

        switch(strokeClass) {
          case StrokeClass.STRUCTURAL:
            length = 0.05 + Math.random() * 0.1; 
            width = 60 + Math.random() * 40; 
            opacity = 0.4; 
            pressure = 0.8; 
            break;
          case StrokeClass.FORM_DEFINING:
            length = 0.02 + Math.random() * 0.04; 
            width = 15 + Math.random() * 15; 
            opacity = 0.8; 
            pressure = 0.6; 
            break;
          case StrokeClass.TRANSITIONAL:
            length = 0.04 + Math.random() * 0.08; 
            width = 30 + Math.random() * 30; 
            opacity = 0.3; 
            pressure = 0.4; 
            angle += (Math.random() - 0.5) * 0.8; 
            break;
          case StrokeClass.ACCENT:
            length = 0.002 + Math.random() * 0.006; 
            width = 1.0 + Math.random() * 1.5; 
            opacity = 1.0; 
            pressure = 1.0; 
            angle = Math.random() * Math.PI * 2; 
            break;
        }

        if (stage === PaintingStage.BACKGROUND_WASH) {
          width *= (1.5 + Math.random() * 1.5); 
          length *= (2.0 + Math.random() * 4.0); 
          // MANDATORY LIMIT: Opacity must never exceed 0.18 for Background Wash class
          opacity = Math.min(opacity * 0.4, 0.18);
          angle += (Math.random() - 0.5) * 0.4;
        }

        if (stage === PaintingStage.SUBJECT_DETAIL || stage === PaintingStage.HIGHTLIGHT_IMPASTO) {
          length *= 0.7;
          width *= 0.6;
          angle += (Math.random() - 0.5) * 1.2; 
        }

        strokes.push({
          x, y, length, width, color: bestCell.color,
          angle, opacity, pressure, stage, strokeClass
        });
      }
    });

    return strokes;
  };

  const drawStroke = useCallback((ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = canvas.width;
    const h = canvas.height;
    const startX = stroke.x * w;
    const startY = stroke.y * h;
    const endX = startX + Math.cos(stroke.angle) * stroke.length * w;
    const endY = startY + Math.sin(stroke.angle) * stroke.length * h;

    ctx.save();

    if (stroke.strokeClass === StrokeClass.STRUCTURAL) {
        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.globalAlpha = stroke.opacity;
        ctx.lineWidth = stroke.width;
        ctx.lineCap = 'butt';
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.stroke();
    } else if (stroke.strokeClass === StrokeClass.FORM_DEFINING || stroke.strokeClass === StrokeClass.ACCENT) {
        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.globalAlpha = stroke.opacity;
        ctx.lineWidth = stroke.width;
        ctx.lineCap = 'round';
        const bristles = stroke.strokeClass === StrokeClass.ACCENT ? 1 : 4;
        for(let b=0; b<bristles; b++) {
          const off = (b - bristles/2) * (stroke.width / bristles);
          ctx.moveTo(startX + off, startY + off);
          ctx.lineTo(endX + off, endY + off);
        }
        ctx.stroke();
    } else { 
        const grad = ctx.createLinearGradient(startX, startY, endX, endY);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(0.5, stroke.color);
        grad.addColorStop(1, 'transparent');
        ctx.strokeStyle = grad;
        ctx.globalAlpha = stroke.opacity;
        ctx.lineWidth = stroke.width;
        ctx.beginPath();
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.stroke();
    }

    ctx.restore();

    if (Math.random() > 0.996 || stroke.width > 60) {
      asmrService.playStrokeSound(startX, stroke.width, stroke.pressure, 0.1 + stroke.length * 0.5);
    }
  }, []);

  const simulate = useCallback(() => {
    if (!simState.isPainting) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { strokes, currentIndex } = simulationRef.current;
    if (currentIndex >= strokes.length) {
      setSimState(prev => ({ ...prev, isPainting: false, progress: 100 }));
      return;
    }

    const speeds = {
      [PaintingStage.UNDERPAINTING_STRICT]: 400,
      [PaintingStage.FORM_CLARIFICATION]: 280,
      [PaintingStage.BACKGROUND_WASH]: 200,
      [PaintingStage.MIDGROUND_FORMS]: 120,
      [PaintingStage.SUBJECT_DETAIL]: 65,
      [PaintingStage.HIGHTLIGHT_IMPASTO]: 45
    };

    const batchSize = speeds[simState.currentStage] || 60;

    for (let i = 0; i < batchSize && (currentIndex + i) < strokes.length; i++) {
      const stroke = strokes[currentIndex + i];
      drawStroke(ctx, stroke);
      if (stroke.stage !== simState.currentStage) {
        setSimState(prev => ({ ...prev, currentStage: stroke.stage }));
      }
    }

    simulationRef.current.currentIndex += batchSize;
    setSimState(prev => ({
      ...prev,
      renderedStrokes: simulationRef.current.currentIndex,
      progress: (simulationRef.current.currentIndex / strokes.length) * 100
    }));

    requestRef.current = requestAnimationFrame(simulate);
  }, [simState.isPainting, simState.currentStage, drawStroke]);

  useEffect(() => {
    if (simState.isPainting) {
      requestRef.current = requestAnimationFrame(simulate);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [simState.isPainting, simulate]);

  return (
    <div className="flex flex-col h-screen w-full bg-[#050505] text-zinc-100 font-sans selection:bg-amber-500/30">
      <header className="px-8 py-5 border-b border-white/5 flex justify-between items-center bg-[#0a0a0a] z-30 sticky top-0 shadow-2xl">
