            <i className="fas fa-brush text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic">V-PAINT <span className="text-amber-500 uppercase tracking-widest text-[9px] ml-2 not-italic bg-amber-500/10 px-2 py-1 rounded">Classification Mode</span></h1>
            <p className="text-[9px] text-zinc-600 uppercase tracking-[0.4em] font-bold mt-1">Multi-Pass Structural Synthesis</p>
          </div>
        </div>

        <div className="flex items-center gap-10">
          {!simState.isPainting && !isAnalyzing && (
            <label className="group bg-zinc-100 hover:bg-amber-500 text-black px-12 py-4 rounded-lg cursor-pointer transition-all duration-300 font-black text-sm tracking-widest flex items-center gap-4 shadow-xl active:scale-95">
              <i className="fas fa-layer-group group-hover:scale-110 transition-transform"></i>
