            {state.isGeneratingPrompt ? <Loader2 className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5 group-hover:rotate-12 transition-transform" />}
            <span className="font-black text-sm uppercase tracking-widest">Execute Production</span>
          </button>
        </footer>
      </aside>

      <main className="flex-1 flex flex-col relative bg-[#050505] min-h-0">
        {!isSidebarOpen && (
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="absolute left-6 top-6 z-40 p-2.5 bg-indigo-600 rounded-xl shadow-lg hover:scale-110 transition-transform border border-white/10 hidden md:block"
          >
            <ChevronRight className="w-5 h-5" />
