        <div className="flex-1 flex flex-col p-4 md:p-8 gap-4 md:gap-6 overflow-hidden">
          <div className="flex-1 min-h-0 flex flex-col relative group">
            <header className="px-4 md:px-6 py-2 md:py-3 bg-[#111] border border-white/5 rounded-t-2xl md:rounded-t-[2.5rem] flex items-center justify-between z-10">
              <div className="flex items-center gap-3">
                <Target className="w-4 h-4 text-indigo-500" />
                <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-white/60">Floor Planner</span>
              </div>
              <div className="flex items-center gap-2 md:gap-4">
                <button 
                  onClick={() => setIsViewfinderOpen(!isViewfinderOpen)}
                  className={`p-1.5 rounded-lg border flex items-center gap-2 transition-all ${
                    isViewfinderOpen ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-white/40'
                  }`}
                >
                  <Eye className="w-3.5 h-3.5" />
                  <span className="text-[8px] font-bold uppercase hidden sm:inline">Camera Viewfinder</span>
                </button>
              </div>
            </header>

            <div className="flex-1 min-h-0 border border-white/5 rounded-b-2xl md:rounded-b-[2.5rem] bg-[#080808] relative overflow-hidden shadow-inner">
              <FloorPlanner 
                state={state}
                onUpdateSubject={(id, updates) => setState(s => ({ ...s, subjects: { ...s.subjects, [id]: { ...s.subjects[id], ...updates } } }))}
                onUpdateCamera={(idx, updates) => {
                  const newCams = [...state.cameras];
                  newCams[idx] = { ...newCams[idx], ...updates };
                  setState(s => ({ ...s, cameras: newCams }));
                }}
                onUpdatePlanner={(u) => setState(s => ({ ...s, ...u }))}
                onSelectCamera={(idx) => setState(s => ({ ...s, activeCameraIndex: idx }))}
              />

              {isViewfinderOpen && (
                <div className="absolute top-4 right-4 w-44 sm:w-64 md:w-80 shadow-2xl z-40 transform transition-all animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="bg-black/90 p-1.5 rounded-2xl border border-white/20 ring-1 ring-black/50 overflow-hidden">
                    <CameraViewfinder state={state} inferredScale={state.inferredShotScale || calculatedShotScale} />
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {(state.isReviewingPrompt || state.isGenerating || state.isReviewingVideoPrompt || state.isGeneratingVideo) && (
          <div className="absolute inset-0 z-[100] bg-[#050505]/95 backdrop-blur-3xl p-4 md:p-8 flex items-center justify-center overflow-y-auto">
            <button 
              onClick={() => setState(s => ({ ...s, isReviewingPrompt: false, isReviewingVideoPrompt: false, isGenerating: false, isGeneratingVideo: false }))}
              className="absolute top-6 right-6 md:top-10 md:right-10 text-white/20 hover:text-white transition-colors"
            >
              <X className="w-8 h-8 md:w-10 md:h-10" />
            </button>

            <div className="max-w-4xl w-full space-y-8 md:space-y-12">
              <div className="text-center space-y-2 md:space-y-4">
                <h3 className="text-4xl md:text-6xl font-black italic tracking-tighter uppercase flex items-center justify-center gap-4 md:gap-6">
                  <Tv className="w-10 h-10 md:w-14 md:h-14 text-indigo-500" />
                  Production Cut
                </h3>
                <p className="text-indigo-400 text-[10px] md:text-xs font-black uppercase tracking-[0.4em] md:tracking-[0.6em] animate-pulse">
                  {state.isGenerating ? "Synthesizing High-Fidelity Textures" : state.isGeneratingVideo ? "Generating Temporal Continuity" : "Analyzing Production Narrative"}
                </p>
              </div>

              {state.generatedImage ? (
                <div className="relative rounded-2xl md:rounded-[3rem] overflow-hidden border-2 md:border-4 border-white/10 shadow-[0_0_150px_rgba(99,102,241,0.1)] aspect-video bg-black/40">
                  {state.generatedVideo ? (
                    <video src={state.generatedVideo} autoPlay loop muted playsInline className="w-full h-full object-cover" />
                  ) : (
                    <img src={state.generatedImage} className="w-full h-full object-cover" />
                  )}
                  {state.isGeneratingVideo && (
                    <div className="absolute inset-0 bg-black/85 flex flex-col items-center justify-center gap-6">
                      <div className="relative">
                        <Loader2 className="w-12 h-12 md:w-20 md:h-20 text-indigo-500 animate-spin" />
                        <Activity className="absolute inset-0 m-auto w-6 h-6 md:w-8 md:h-8 text-indigo-400 animate-pulse" />
                      </div>
                      <div className="text-center">
                         <p className="text-white font-black tracking-widest text-xs md:text-sm uppercase">{state.videoStatus}</p>
                         <p className="text-white/20 text-[8px] md:text-[10px] font-bold uppercase mt-2 tracking-widest">Veo Engine active</p>
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <div className="bg-[#111] border border-white/10 p-6 md:p-12 rounded-2xl md:rounded-[3rem] text-left font-serif text-lg md:text-2xl text-white/80 italic leading-relaxed shadow-2xl relative overflow-hidden group">
                  <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600 transition-all group-hover:w-3" />
                  "{state.draftPrompt}"
                </div>
              )}

              <div className="flex flex-col sm:flex-row gap-4 md:gap-6 justify-center">
                {!state.generatedImage && (
                  <button 
                    onClick={handleRenderImage}
                    disabled={state.isGenerating}
                    className="bg-white text-black font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    {state.isGenerating ? <Loader2 className="w-6 h-6 md:w-8 md:h-8 animate-spin" /> : <MonitorPlay className="w-6 h-6 md:w-8 md:h-8" />}
                    <div className="text-left">
                      <div className="text-base md:text-xl font-black uppercase">Commit Render</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Cost: ₹{COST_PER_IMAGE.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedImage && !state.generatedVideo && !state.isGeneratingVideo && (
                  <button 
                    onClick={handleGenerateVideo}
                    className="bg-indigo-600 text-white font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:bg-indigo-500 hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    <Play className="w-6 h-6 md:w-8 md:h-8" />
                    <div className="text-left">
                      <div className="text-base md:text-xl uppercase font-black">Animate Sequence</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Cost: ₹{COST_PER_VIDEO.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedVideo && (
                  <a 
                    href={state.generatedVideo}
                    download="production_output.mp4"
                    className="bg-emerald-600 text-white font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:bg-emerald-500 hover:scale-105 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    <Download className="w-6 h-6 md:w-8 md:h-8" />
                    <div className="text-left">
                      <div className="text-base md:text-xl uppercase font-black">Export Master</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Download MP4</div>
                    </div>
                  </a>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Camera, Layers, Wand2, Loader2, X, Play, Download, 
  Target, MonitorPlay, Users, Landmark, 
  Tv, Move, ZoomIn, Activity, ShieldCheck, ChevronLeft, ChevronRight, Settings2, Eye, Menu, Wallet, Sun
} from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES, COST_PER_IMAGE, COST_PER_VIDEO } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import ShotScalePicker from './components/ShotScalePicker';
import LightRig from './components/LightRig';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo } from './services/geminiService';

// Redundant type declarations for AIStudio removed.
// The environment provides these types globally, and re-declaring them caused type collisions.

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isViewfinderOpen, setIsViewfinderOpen] = useState(true);

  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: { positions: new Array(8).fill(false) },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [{
      id: 'cam-1', x: 0, z: 0, rotation: 0,
      model: CAMERA_MODELS[0], lens: LENSES[2].label, verticalAngle: VERTICAL_ANGLES[1],
    }],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
    plannerOffset: { x: 0, z: 0 },
    usage: { totalSpent: 0, analysis: 0, render: 0, video: 0, tokens: 0 },
    inferredShotScale: undefined
  });

  const activeCamera = state.cameras[state.activeCameraIndex];

  const calculatedShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const dist = Math.sqrt(dx*dx + dz*dz);

    const sensorHeight = 24; 
    const frameHeightAtDist = (sensorHeight * dist) / mm;
    const charHeightPercent = (6.0 / frameHeightAtDist) * 100;

    if (charHeightPercent > 150) return "Extreme Close Up (ECU)";
    if (charHeightPercent > 70) return "Close Up (CU)";
    if (charHeightPercent > 40) return "Medium Shot (MS)";
    if (charHeightPercent > 20) return "Long Shot (LS)";
    if (charHeightPercent > 10) return "Wide Shot (WS)";
    return "Extreme Wide Shot (EWS)";
  }, [activeCamera, state.subjects.a]);

  const handleGeneratePrompt = async () => {
    setState(s => ({ ...s, isGeneratingPrompt: true }));
    try {
      // Pass the inferred scale explicitly to ensure prompt priority matches the UI
      const finalState = { ...state, inferredShotScale: state.inferredShotScale || calculatedShotScale };
      const { script, cost, tokens } = await generateDraftPrompt(finalState);

      setState(s => ({
        ...s,
        draftPrompt: script,
        isGeneratingPrompt: false,
        isReviewingPrompt: true,
        usage: {
          ...s.usage,
          analysis: s.usage.analysis + cost,
          tokens: s.usage.tokens + tokens,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      alert("Error: The analysis payload was too large or the proxy timed out. Try removing one reference image.");
      setState(s => ({ ...s, isGeneratingPrompt: false }));
    }
  };

  const handleRenderImage = async () => {
    // Rely on globally pre-configured window.aistudio
    if ((window as any).aistudio) {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
    }

    setState(s => ({ ...s, isGenerating: true }));
    try {
      const { url, cost } = await generateStudioImage(state, state.draftPrompt);
      setState(s => ({
        ...s,
        generatedImage: url,
        isGenerating: false,
        isReviewingPrompt: false,
        isReviewingVideoPrompt: true,
        usage: {
          ...s.usage,
          render: s.usage.render + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e: any) {
      console.error(e);
      // Reset key selection if the requested entity was not found (per Veo guidelines)
      if (e?.message?.includes("Requested entity was not found.") && (window as any).aistudio) {
        await (window as any).aistudio.openSelectKey();
      }
      setState(s => ({ ...s, isGenerating: false }));
    }
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;

    setState(s => ({ ...s, isGeneratingVideo: true }));
    try {
      const { url, cost } = await generateStudioVideo(state, state.draftPrompt, state.generatedImage, (status) => {
        setState(s => ({ ...s, videoStatus: status }));
      });
      setState(s => ({
        ...s,
        generatedVideo: url,
        isGeneratingVideo: false,
        isReviewingVideoPrompt: false,
        usage: {
          ...s.usage,
          video: s.usage.video + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e: any) {
      console.error(e);
      // Reset key selection if the requested entity was not found (per Veo guidelines)
      if (e?.message?.includes("Requested entity was not found.") && (window as any).aistudio) {
        await (window as any).aistudio.openSelectKey();
      }
      setState(s => ({ ...s, isGeneratingVideo: false }));
    }
  };

  const updateActiveCamera = (updates: Partial<CameraConfig>) => {
    const newCams = [...state.cameras];
    newCams[state.activeCameraIndex] = { ...newCams[state.activeCameraIndex], ...updates };
    setState(s => ({ ...s, cameras: newCams }));
  };

  const toggleLight = (index: number) => {
    setState(s => {
      const newPos = [...s.lighting.positions];
      newPos[index] = !newPos[index];
      return { ...s, lighting: { ...s.lighting, positions: newPos } };
    });
  };

  return (
    <div className="flex h-screen bg-[#050505] text-white overflow-hidden flex-col md:flex-row">
      <header className="md:hidden p-4 border-b border-white/5 flex items-center justify-between bg-[#0d0d0d] z-[60]">
        <div className="flex items-center gap-2">
          <Landmark className="w-6 h-6 text-indigo-500" />
          <h1 className="text-lg font-black tracking-tighter uppercase">Studio AI</h1>
        </div>
        <button 
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="p-2 bg-white/5 rounded-lg border border-white/10"
        >
          {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </header>

      <aside className={`
        fixed inset-0 z-50 bg-[#0d0d0d] transition-transform duration-300 md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        w-full md:w-[360px] lg:w-[400px] flex flex-col border-r border-white/5 shadow-2xl
      `}>
        <header className="hidden md:flex p-6 border-b border-white/5 items-center justify-between">
          <div className="flex items-center gap-3">
            <Landmark className="w-7 h-7 text-indigo-500" />
            <h1 className="text-xl font-black tracking-tighter uppercase">Studio AI</h1>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="p-1.5 hover:bg-white/5 rounded-md text-white/40">
            <ChevronLeft className="w-5 h-5" />
          </button>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">
          <section className="bg-indigo-600/10 rounded-2xl border border-indigo-500/20 p-5 space-y-4 shadow-lg">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] flex items-center gap-2">
                <Wallet className="w-3 h-3" /> Production Wallet
              </h2>
              <span className="text-sm font-mono font-bold text-white tracking-tight">
                ₹{state.usage.totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 4 })}
              </span>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Renders</p>
                <p className="text-xs font-mono text-indigo-400">₹{state.usage.render.toFixed(2)}</p>
              </div>
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Tokens</p>
                <p className="text-xs font-mono text-indigo-400">{state.usage.tokens.toLocaleString()}</p>
              </div>
            </div>
          </section>

          <section className="space-y-4">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Layers className="w-3 h-3" /> Asset Library
            </h2>
            <div className="grid grid-cols-3 gap-2">
              {REFERENCE_SLOTS.map(slot => (
                <ReferenceUploader 
                  key={slot.id} 
                  slot={slot} 
                  dataUrl={state.references[slot.id].dataUrl}
                  onUpload={(url, mime) => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: url, mimeType: mime } }
                  }))}
                  onRemove={() => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: undefined } }
                  }))}
                />
              ))}
            </div>
          </section>

          <section className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-5">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Settings2 className="w-3 h-3" /> Optical Config
            </h2>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1.5">
                  <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Body</label>
                  <select 
                    value={activeCamera.model}
                    onChange={(e) => updateActiveCamera({ model: e.target.value })}
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold focus:border-indigo-500"
                  >
                    {CAMERA_MODELS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Lens</label>
                  <select 
                    value={activeCamera.lens}
                    onChange={(e) => updateActiveCamera({ lens: e.target.value })}
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold focus:border-indigo-500"
                  >
                    {LENSES.map(l => <option key={l.label} value={l.label}>{l.label}</option>)}
                  </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Elevation</label>
                <select 
