async function downscaleImage(dataUrl: string, maxWidth = 128, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

const getFovAngle = (lens: string) => {
  const mmMatch = lens.match(/(\d+)mm/);
  const focalLength = mmMatch ? parseInt(mmMatch[1]) : 50;
  return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
};

const filterVisibleLandmarks = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const fov = getFovAngle(cam.lens);
  const rotRad = -cam.rotation * (Math.PI / 180);

  return state.landmarks.filter(lm => {
    const dx = lm.x - cam.x;
    const dz = lm.z - cam.z;
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

    if (localZ <= 0.5) return false; // Behind camera

    const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
    const angleToLm = Math.abs(Math.atan2(localX, localZ) * (180 / Math.PI));

    return angleToLm < (fov / 2) + 5; // Within cone (with small buffer)
  }).map(lm => ({
    label: lm.label,
    depth: Math.sqrt((lm.x - cam.x)**2 + (lm.z - cam.z)**2).toFixed(1) + "ft",
    description: lm.description
  }));
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const visibleLandmarks = filterVisibleLandmarks(state);
  const shotScale = state.inferredShotScale || "Medium Shot (MS)";

  const processedRefs = await Promise.all(
    Object.keys(state.references).map(async (key) => {
      const ref = state.references[key as any];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 128, 0.3);
          return { key, data, mimeType };
        } catch (e) { return null; }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedRefs.forEach(ref => {
    if (ref) {
      parts.push({ text: `REFERENCE_${ref.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: ref.data, mimeType: ref.mimeType } });
    }
  });

  const compositionGuide = `
=== SPATIAL_METADATA ===
SHOT_SCALE: ${shotScale}
LENS: ${activeCamera.lens}
CAMERA_BODY: ${activeCamera.model}
ENVIRONMENTAL_ANCHORS: ${JSON.stringify(visibleLandmarks)}
SUBJECT_COUNT: ${state.subjects.length}
`;

  const systemInstruction = `You are a Virtual Production Prompt Architect.
Synthesize a single cohesive JSON prompt for an image generator.

The output MUST contain:
1. "cinematic_prose": An atmospheric narrative incorporating landmarks and subjects.
2. "environmental_anchors": A list of visible background landmarks with their specific depths and roles in the scene.
3. "technical_spec": Detailed camera and lens settings.

CRITICAL: Use the ENVIRONMENTAL_ANCHORS metadata to describe relative distance and parallax.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: compositionGuide },
        { text: "Generate the full JSON production specification." }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          environmental_anchors: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                depth: { type: Type.STRING },
                description: { type: Type.STRING }
              }
            }
          },
          technical_spec: { type: Type.OBJECT, properties: { lens: { type: Type.STRING } } }
        }
      }
    }
  });

  const text = response.text || "{}";
  return { script: text, cost: (text.length / 1000) * COST_PER_1K_TOKENS, tokens: text.length / 4 };
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [{ text: `PROMPT_SPEC: ${draftJson}` }];

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9", imageSize: "1K" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed.");

  return { url: `data:image/png;base64,${imgPart.inlineData.data}`, cost: COST_PER_IMAGE };
};

export const generateStudioVideo = async (state: StudioState, script: string, baseImage: string, onStatusChange: (s: string) => void) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Preparing Video...");
  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: script,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Processing Frames...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return { url: URL.createObjectURL(blob), cost: COST_PER_VIDEO };
};

