import { Camera, RotateCw, Eye, MapPin } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig, Landmark } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: string, updates: Partial<SubjectConfig>) => void;
  onUpdateLandmark: (id: string, updates: Partial<Landmark>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onUpdatePlanner: (updates: { zoom?: number; offset?: { x: number; z: number } }) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state, onUpdateSubject, onUpdateLandmark, onUpdateCamera, onUpdatePlanner, onSelectCamera 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'pan'; 
    target: 'subject' | 'camera' | 'landmark' | 'background';
    id: any;
    startX?: number;
    startY?: number;
    initialOffset?: { x: number; z: number };
  } | null>(null);

  const startDrag = (type: any, target: any, id: any) => (e: any) => {
    e.stopPropagation();
    const clientX = e.clientX || e.touches?.[0]?.clientX;
    const clientY = e.clientY || e.touches?.[0]?.clientY;
    if (target === 'camera' && type === 'move') onSelectCamera(id);
    setDragState({ type, target, id, startX: clientX, startY: clientY, initialOffset: { ...state.plannerOffset } });
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const range = 50 / state.plannerZoom;

    if (dragState.type === 'pan') {
      const dx = (clientX - (dragState.startX || 0)) / rect.width * (range * 2);
      const dz = -(clientY - (dragState.startY || 0)) / rect.height * (range * 2);
      onUpdatePlanner({ offset: { x: (dragState.initialOffset?.x || 0) + dx, z: (dragState.initialOffset?.z || 0) + dz } });
      return;
    }

    const coordX = ((clientX - rect.left) / rect.width - 0.5) * (range * 2) - state.plannerOffset.x;
    const coordZ = (1 - (clientY - rect.top) / rect.height) * (range * 2) - state.plannerOffset.z;

    if (dragState.type === 'move') {
      if (dragState.target === 'subject') onUpdateSubject(dragState.id, { x: coordX, z: coordZ });
      else if (dragState.target === 'camera') onUpdateCamera(dragState.id, { x: coordX, z: coordZ });
      else if (dragState.target === 'landmark') onUpdateLandmark(dragState.id, { x: coordX, z: coordZ });
    } else {
      const targetObj: any = dragState.target === 'subject' ? state.subjects.find(s => s.id === dragState.id) : state.cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + (targetObj.x + state.plannerOffset.x) / (range * 2));
      const objScreenY = rect.top + rect.height * (1 - (targetObj.z + state.plannerOffset.z) / (range * 2));
      let angle = (Math.atan2(clientX - objScreenX, -(clientY - objScreenY)) * 180 / Math.PI + 360) % 360;
      if (dragState.type === 'rotate-body') onUpdateSubject(dragState.id, { rotation: angle });
      else if (dragState.type === 'rotate-gaze') onUpdateSubject(dragState.id, { gaze: angle });
    }
  }, [dragState, state.plannerZoom, state.plannerOffset, state.subjects, state.cameras]);

  useEffect(() => {
    const move = (e: any) => handleInteraction(e.clientX || e.touches?.[0]?.clientX, e.clientY || e.touches?.[0]?.clientY);
    const end = () => setDragState(null);
    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', end);
    window.addEventListener('touchmove', move);
    window.addEventListener('touchend', end);
    return () => {
      window.removeEventListener('mousemove', move);
      window.removeEventListener('mouseup', end);
      window.removeEventListener('touchmove', move);
      window.removeEventListener('touchend', end);
    };
  }, [handleInteraction]);

  const getPos = (obj: { x: number, z: number }) => {
    const range = 50 / state.plannerZoom;
    return { 
