const CameraViewfinder: React.FC<{ state: StudioState, inferredScale?: string }> = ({ state, inferredScale }) => {
  const cam = state.cameras[state.activeCameraIndex];
  const mm = parseInt(cam.lens.match(/\d+/)?.[0] || "50");
  const sensorHeight = 24;
  const aspect = 16 / 9;

  const project = (obj: { x: number, z: number }) => {
    const dx = obj.x - cam.x;
    const dz = obj.z - cam.z;
    const rotRad = -cam.rotation * (Math.PI / 180);
    const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

    if (localZ <= 0.1) return null;

    const frameHeightAtZ = (sensorHeight * localZ) / mm;
    const frameWidthAtZ = frameHeightAtZ * aspect;
    const screenX = 50 + (localX / (frameWidthAtZ / 2)) * 50;
    const heightPct = (6.0 / frameHeightAtZ) * 100;

    return { x: screenX, heightPct, dist: localZ, visible: screenX > -20 && screenX < 120 };
  };

  return (
    <div className="relative w-full aspect-video bg-[#010101] rounded-2xl border border-white/10 overflow-hidden shadow-2xl">
      <div className="absolute inset-0 z-10 opacity-10 pointer-events-none border border-white/20" style={{ backgroundImage: 'linear-gradient(to right, transparent 33.3%, #fff 33.3%, #fff 33.4%, transparent 33.4%, transparent 66.6%, #fff 66.6%, #fff 66.7%, transparent 66.7%), linear-gradient(to bottom, transparent 33.3%, #fff 33.3%, #fff 33.4%, transparent 33.4%, transparent 66.6%, #fff 66.6%, #fff 66.7%, transparent 66.7%)' }} />

      {state.landmarks.map(lm => {
        const p = project(lm);
        if (!p || !p.visible) return null;
        return (
          <div key={lm.id} className="absolute flex flex-col items-center transition-all duration-300" style={{ left: `${p.x}%`, top: '40%', opacity: Math.max(0.1, 1 - p.dist/200) }}>
             <MapPin className="text-emerald-500/30" style={{ width: p.heightPct * 2 }} />
             <span className="text-[4px] font-black uppercase text-emerald-500/40">{lm.label}</span>
          </div>
        );
      })}

      {state.subjects.map(sub => {
        const p = project(sub);
        if (!p || !p.visible) return null;
        return (
          <div key={sub.id} className="absolute flex flex-col items-center transition-all duration-300" style={{ left: `${p.x}%`, top: `${50 - p.heightPct/2}%`, height: `${p.heightPct}%`, zIndex: Math.round(1000 - p.dist) }}>
             <div className="w-1/2 aspect-square rounded-full border border-indigo-500 bg-indigo-500/20" />
             <div className="w-full flex-1 border-x border-t border-indigo-500/50 bg-indigo-500/10 rounded-t-xl" />
             <span className="text-[5px] font-black uppercase text-indigo-400 mt-1">{sub.label}</span>
          </div>
        );
      })}

      <div className="absolute top-2 left-2 flex gap-2">
         <span className="bg-red-600 px-1.5 py-0.5 rounded text-[6px] font-bold uppercase animate-pulse">REC</span>
         <span className="bg-white/10 px-1.5 py-0.5 rounded text-[6px] font-bold uppercase font-mono">{inferredScale}</span>
      </div>
    </div>
  );
};

