import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, SubjectConfig, Landmark } from "../types";

export const COST_PER_IMAGE = 2.50;
export const COST_PER_VIDEO = 12.60;
export const COST_PER_1K_TOKENS = 0.0084;

async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.7): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

/**
 * Analyzes a background image to detect landmarks and their spatial placement.
 */
export const analyzeBackground = async (dataUrl: string): Promise<Partial<Landmark>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const { data, mimeType } = await downscaleImage(dataUrl, 1024, 0.8);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data, mimeType } },
        { text: "Identify key background landmarks and features in this image. For each landmark, provide a label, a short description, and an estimated relative depth (Z from 20 to 100, where 100 is far horizon) and horizontal position (X from -30 to 30, where 0 is center)." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            label: { type: Type.STRING },
            description: { type: Type.STRING },
            x: { type: Type.NUMBER },
            z: { type: Type.NUMBER }
          },
          required: ["label", "description", "x", "z"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    console.error("Failed to parse background analysis", e);
    return [];
  }
};

const getFovAngle = (lens: string) => {
  const mmMatch = lens.match(/(\d+)mm/);
  const focalLength = mmMatch ? parseInt(mmMatch[1]) : 50;
  return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
};

const filterVisibleLandmarks = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const fov = getFovAngle(cam.lens);
  const rotRad = -cam.rotation * (Math.PI / 180);

  return state.landmarks.filter(lm => {
    const dx = lm.x - cam.x;
    const dz = lm.z - cam.z;
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

    if (localZ <= 0.5) return false; // Behind camera

    const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
    const angleToLm = Math.abs(Math.atan2(localX, localZ) * (180 / Math.PI));

    // Within cone (with buffer)
    return angleToLm < (fov / 2) + 10; 
  }).map(lm => ({
    label: lm.label,
    depth: Math.sqrt((lm.x - cam.x)**2 + (lm.z - cam.z)**2).toFixed(1) + "ft",
    description: lm.description
  }));
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const visibleLandmarks = filterVisibleLandmarks(state);
  const shotScale = state.inferredShotScale || "Medium Shot (MS)";

  const processedRefs = await Promise.all(
    Object.keys(state.references).map(async (key) => {
      const ref = state.references[key as any];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 128, 0.3);
          return { key, data, mimeType };
        } catch (e) { return null; }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedRefs.forEach(ref => {
    if (ref) {
      parts.push({ text: `REFERENCE_${ref.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: ref.data, mimeType: ref.mimeType } });
    }
  });

  const compositionGuide = `
=== PRODUCTION_METADATA ===
SHOT_SCALE: ${shotScale}
LENS: ${activeCamera.lens}
CAMERA_BODY: ${activeCamera.model}
ELEVATION: ${activeCamera.verticalAngle}
VISIBLE_LANDMARKS: ${JSON.stringify(visibleLandmarks)}
SUBJECTS_DATA: ${JSON.stringify(state.subjects.map(s => ({ label: s.label, pos: { x: s.x.toFixed(1), z: s.z.toFixed(1) }, rotation: s.rotation })))}
`;

  const systemInstruction = `You are a Virtual Production Prompt Architect.
Synthesize a single cohesive JSON production spec.

The output MUST contain:
1. "cinematic_prose": A rich narrative that weaves the detected landmarks, subjects, and lighting into a single vision.
2. "environmental_anchors": A list containing ONLY the visible landmarks in the current camera view, including their relative labels, specific depth values (from the provided metadata), and descriptions.
3. "technical_spec": Comprehensive technical detail of the shot.

CRITICAL: If VISIBLE_LANDMARKS is empty, do not hallucinate background landmarks; focus on the provided background reference.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: compositionGuide },
        { text: "Generate the full JSON specification for production." }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          environmental_anchors: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                depth: { type: Type.STRING },
                description: { type: Type.STRING }
              }
            }
          },
          technical_spec: {
            type: Type.OBJECT,
            properties: {
              camera: { type: Type.STRING },
              lens: { type: Type.STRING },
              shot_scale: { type: Type.STRING }
            }
          }
        },
        required: ["cinematic_prose", "environmental_anchors"]
      }
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 1000;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Extract prompts for image generation
  let cinematic_prose = draftJson;
  try {
    const p = JSON.parse(draftJson);
    cinematic_prose = p.cinematic_prose || draftJson;
  } catch (e) {}

  const activeCamera = state.cameras[state.activeCameraIndex];

  // Prepare references for image generation model
  const processedAssets = await Promise.all(
    Object.keys(state.references).map(async (key) => {
      const ref = state.references[key as any];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
          return { key, data, mimeType };
        } catch (e) { return null; }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedAssets.forEach(asset => {
    if (asset) {
      parts.push({ text: `ASSET_${asset.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: asset.data, mimeType: asset.mimeType } });
    }
  });

  parts.push({ text: `SCENE_NARRATIVE: ${cinematic_prose}\nSHOT_INFO: ${activeCamera.lens}, ${activeCamera.verticalAngle}, ${state.inferredShotScale || 'Medium Shot'}` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { aspectRatio: "16:9", imageSize: "1K" } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed.");

  return { 
    url: `data:image/png;base64,${imgPart.inlineData.data}`, 
    cost: COST_PER_IMAGE 
  };
};

export const generateStudioVideo = async (
  state: StudioState, 
  script: string, 
  baseImage: string, 
  onStatusChange: (s: string) => void
): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Preparing Video Synthesis...");

  const base64Data = baseImage.split(',')[1];

  let prose = script;
  try {
    const p = JSON.parse(script);
    prose = p.cinematic_prose || script;
  } catch(e) {}

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Animate this cinematic scene. Focus on subtle motion and depth. Narrative: ${prose}`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Generating Sequence...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video synthesis failed.");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return { url: URL.createObjectURL(blob), cost: COST_PER_VIDEO };
};

