  };

  const removeLandmark = (id: string) => {
    setState(s => ({ ...s, landmarks: s.landmarks.filter(lm => lm.id !== id) }));
  };

  const handleAssetUpload = async (id: ReferenceType, url: string, mime: string) => {
    setState(s => ({
      ...s,
      references: { ...s.references, [id]: { ...s.references[id], dataUrl: url, mimeType: mime } }
    }));

    if (id === 'background') {
      setIsAnalyzingBackground(true);
      setActiveTab('scenery');
      try {
        const detected = await analyzeBackground(url);
        const newLandmarks: Landmark[] = detected.map((d, i) => ({
          id: `detected-${Date.now()}-${i}`,
          label: d.label || 'Feature',
          description: d.description || '',
          x: d.x ?? 0,
          z: d.z ?? 50
        }));
        setState(s => ({ ...s, landmarks: newLandmarks }));
      } catch (e) {
        console.error("Background analysis failed", e);
      } finally {
        setIsAnalyzingBackground(false);
      }
    }
  };

  const handleGeneratePrompt = async () => {
    setState(s => ({ ...s, isGeneratingPrompt: true }));
    try {
      const { script, cost, tokens } = await generateDraftPrompt({ ...state, inferredShotScale: state.inferredShotScale || calculatedShotScale });
      setState(s => ({ 
        ...s, 
        draftPrompt: script, 
        isGeneratingPrompt: false, 
        isReviewingPrompt: true, 
        usage: { 
          ...s.usage, 
          totalSpent: s.usage.totalSpent + cost,
          tokens: s.usage.tokens + tokens,
          analysis: s.usage.analysis + cost
        } 
      }));
    } catch (e) {
      alert("Synthesis engine error. Try again with fewer references.");
      setState(s => ({ ...s, isGeneratingPrompt: false }));
    }
  };

  const proseDisplay = useMemo(() => {
    try { return JSON.parse(state.draftPrompt).cinematic_prose || state.draftPrompt; } catch (e) { return state.draftPrompt; }
  }, [state.draftPrompt]);

  return (
    <div className="flex h-screen bg-[#050505] text-white overflow-hidden flex-col md:flex-row">
      <aside className={`${isSidebarOpen ? 'w-full md:w-[400px]' : 'w-0'} transition-all bg-[#0d0d0d] flex flex-col border-r border-white/5`}>
        <header className="p-6 border-b border-white/5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <LandmarkIcon className="w-7 h-7 text-indigo-500" />
            <h1 className="text-xl font-black tracking-tighter uppercase">Studio AI</h1>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="md:hidden"><X /></button>
        </header>

        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
          <div className="flex bg-white/5 p-1 rounded-xl gap-1">
            <button onClick={() => setActiveTab('talent')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'talent' ? 'bg-indigo-600' : 'hover:bg-white/5'}`}>Talent</button>
            <button onClick={() => setActiveTab('scenery')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'scenery' ? 'bg-indigo-600 shadow-lg' : 'hover:bg-white/5'}`}>Scenery</button>
          </div>

          {activeTab === 'talent' ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black text-white/30 uppercase tracking-widest">Cast & Talent</h2>
                <button onClick={addSubject} className="p-1.5 bg-indigo-600 rounded-lg hover:scale-110 transition-transform shadow-lg"><Plus className="w-4 h-4" /></button>
              </div>
              {state.subjects.map((sub) => (
                <div key={sub.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-3 shadow-inner">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <Users className="w-3 h-3 text-indigo-400" />
                      <input value={sub.label} onChange={(e) => updateSubject(sub.id, { label: e.target.value })} className="bg-transparent text-xs font-bold focus:outline-none focus:text-indigo-400 w-full" />
                    </div>
                    <button onClick={() => removeSubject(sub.id)} className="text-white/20 hover:text-red-500 transition-colors"><Trash2 className="w-3 h-3" /></button>
                  </div>
                  <OrientationSlider config={sub} activeCamera={activeCamera} onChange={(v) => updateSubject(sub.id, { rotation: v })} />
                  <GazeSelector subjectId="a" config={sub} activeCamera={activeCamera} onChange={(v) => updateSubject(sub.id, { gaze: v })} />
                </div>
              ))}
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black text-white/30 uppercase tracking-widest">Environment Landmarks</h2>
                <button onClick={addLandmark} className="p-1.5 bg-emerald-600 rounded-lg hover:scale-110 transition-transform shadow-lg"><Plus className="w-4 h-4" /></button>
              </div>

              {isAnalyzingBackground && (
                <div className="bg-emerald-500/10 border border-emerald-500/20 p-4 rounded-2xl flex items-center gap-3 animate-pulse">
                  <ScanSearch className="w-5 h-5 text-emerald-500 animate-bounce" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Detecting landmarks...</p>
                </div>
