              {state.landmarks.map(lm => (
                <div key={lm.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-3 shadow-inner">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                       <MapPin className="w-3 h-3 text-emerald-500" />
                       <input value={lm.label} onChange={(e) => updateLandmark(lm.id, { label: e.target.value })} className="bg-transparent text-xs font-bold focus:outline-none focus:text-emerald-400 w-full" />
                    </div>
                    <button onClick={() => removeLandmark(lm.id)} className="text-white/20 hover:text-red-500 transition-colors"><Trash2 className="w-3 h-3" /></button>
                  </div>
                  <textarea 
