                       <button onClick={() => { navigator.clipboard.writeText(state.draftPrompt); setCopying(true); setTimeout(() => setCopying(false), 2000); }} className="text-[10px] font-black uppercase text-indigo-400 flex items-center gap-2 hover:text-indigo-300 transition-colors">
                         {copying ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />} {copying ? 'Copied' : 'Copy'}
