import { Camera, MapPin } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig, Landmark } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: string, updates: Partial<SubjectConfig>) => void;
  onUpdateLandmark: (id: string, updates: Partial<Landmark>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onUpdatePlanner: (updates: { zoom?: number; offset?: { x: number; z: number } }) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state, onUpdateSubject, onUpdateLandmark, onUpdateCamera, onUpdatePlanner, onSelectCamera 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'pan'; 
    target: 'subject' | 'camera' | 'landmark' | 'background';
    id: any;
    startX: number;
    startY: number;
    initialOffset: { x: number; z: number };
  } | null>(null);

  const [touchState, setTouchState] = useState<{
    type: 'pan' | 'pinch';
    initialDist?: number;
    initialZoom?: number;
    initialOffset?: { x: number; z: number };
    startX?: number;
    startY?: number;
  } | null>(null);

  const getRange = useCallback(() => 50 / state.plannerZoom, [state.plannerZoom]);

  const startDrag = (type: 'move' | 'rotate-body' | 'pan', target: any, id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();

    // Middle mouse button is 1
    const isMiddleMouse = (e as React.MouseEvent).button === 1;
    const finalType = isMiddleMouse ? 'pan' : type;
    const finalTarget = isMiddleMouse ? 'background' : target;

    const clientX = 'clientX' in e ? e.clientX : e.touches[0].clientX;
    const clientY = 'clientY' in e ? e.clientY : e.touches[0].clientY;

    if (finalTarget === 'camera' && finalType === 'move') onSelectCamera(id);

    setDragState({ 
      type: finalType, 
      target: finalTarget, 
      id, 
      startX: clientX, 
      startY: clientY, 
      initialOffset: { ...state.plannerOffset } 
    });
  };

  const handleWheel = (e: React.WheelEvent) => {
    const delta = e.deltaY;
    const zoomFactor = 1.1;
    const newZoom = delta > 0 ? state.plannerZoom / zoomFactor : state.plannerZoom * zoomFactor;
    // Constrain zoom
    const clampedZoom = Math.max(0.1, Math.min(5, newZoom));
    onUpdatePlanner({ zoom: clampedZoom });
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (e.touches.length === 1) {
      // Single touch: Pan
      setTouchState({
        type: 'pan',
        startX: e.touches[0].clientX,
        startY: e.touches[0].clientY,
        initialOffset: { ...state.plannerOffset }
      });
    } else if (e.touches.length === 2) {
      // Multi touch: Pinch
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      setTouchState({
        type: 'pinch',
        initialDist: dist,
        initialZoom: state.plannerZoom
      });
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (!touchState) return;

    if (touchState.type === 'pan' && e.touches.length === 1) {
      const rect = containerRef.current!.getBoundingClientRect();
      const range = getRange();
      const dx = (e.touches[0].clientX - touchState.startX!) / rect.width * (range * 2);
      const dz = -(e.touches[0].clientY - touchState.startY!) / rect.height * (range * 2);
      onUpdatePlanner({ offset: { x: touchState.initialOffset!.x + dx, z: touchState.initialOffset!.z + dz } });
    } else if (touchState.type === 'pinch' && e.touches.length === 2) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      const scale = dist / touchState.initialDist!;
      const newZoom = touchState.initialZoom! * scale;
      const clampedZoom = Math.max(0.1, Math.min(5, newZoom));
      onUpdatePlanner({ zoom: clampedZoom });
    }
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!dragState || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const range = getRange();

    if (dragState.type === 'pan') {
      const dx = (e.clientX - dragState.startX) / rect.width * (range * 2);
      const dz = -(e.clientY - dragState.startY) / rect.height * (range * 2);
      onUpdatePlanner({ offset: { x: dragState.initialOffset.x + dx, z: dragState.initialOffset.z + dz } });
      return;
    }

    const coordX = ((e.clientX - rect.left) / rect.width - 0.5) * (range * 2) - state.plannerOffset.x;
    const coordZ = (1 - (e.clientY - rect.top) / rect.height - 0.5) * (range * 2) - state.plannerOffset.z;

    if (dragState.type === 'move') {
      if (dragState.target === 'subject') onUpdateSubject(dragState.id, { x: coordX, z: coordZ });
      else if (dragState.target === 'camera') onUpdateCamera(dragState.id, { x: coordX, z: coordZ });
      else if (dragState.target === 'landmark') onUpdateLandmark(dragState.id, { x: coordX, z: coordZ });
    } else if (dragState.type === 'rotate-body') {
      const targetObj: any = dragState.target === 'subject' ? state.subjects.find(s => s.id === dragState.id) : state.cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + (targetObj.x + state.plannerOffset.x) / (range * 2));
      const objScreenY = rect.top + rect.height * (0.5 - (targetObj.z + state.plannerOffset.z) / (range * 2));
      let angle = (Math.atan2(e.clientX - objScreenX, -(e.clientY - objScreenY)) * 180 / Math.PI + 360) % 360;
      onUpdateSubject(dragState.id, { rotation: angle });
    }
  }, [dragState, state.plannerOffset, state.subjects, state.cameras, getRange, onUpdatePlanner, onUpdateSubject, onUpdateCamera, onUpdateLandmark]);

  useEffect(() => {
    const end = () => {
      setDragState(null);
      setTouchState(null);
    };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', end);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', end);
    };
  }, [handleMouseMove]);

  const getPos = (obj: { x: number, z: number }) => {
    const range = getRange();
    // Centering the logic: 0,0 should be at center of screen if offset is 0,0
    const leftVal = (((obj.x + state.plannerOffset.x) / (range * 2)) + 0.5) * 100;
    const bottomVal = (((obj.z + state.plannerOffset.z) / (range * 2)) + 0.5) * 100;
    return { 
      left: `${leftVal}%`, 
      bottom: `${bottomVal}%` 
    };
  };

  return (
    <div 
      ref={containerRef} 
      onMouseDown={startDrag('pan', 'background', null)} 
      onWheel={handleWheel}
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={() => setTouchState(null)}
      className="w-full h-full relative overflow-hidden bg-[#050505] cursor-grab active:cursor-grabbing touch-none select-none"
    >
      {/* Grid */}
      <div 
        className="absolute inset-0 opacity-10 pointer-events-none" 
        style={{ 
          backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
          backgroundSize: `${20 * state.plannerZoom}px ${20 * state.plannerZoom}px`, 
          backgroundPosition: `${(state.plannerOffset.x * 10 * state.plannerZoom) + (containerRef.current?.offsetWidth || 0) / 2}px ${(-state.plannerOffset.z * 10 * state.plannerZoom) + (containerRef.current?.offsetHeight || 0) / 2}px` 
        }} 
      />

      {state.subjects.map(sub => (
        <div key={sub.id} style={getPos(sub)} className="absolute -translate-x-1/2 translate-y-1/2 z-20 group">
          <div className="relative w-16 h-16 flex items-center justify-center">
            {/* Subject body/move handle */}
            <div 
              onMouseDown={startDrag('move', 'subject', sub.id)} 
              className="absolute inset-2 rounded-full border-2 border-indigo-500 bg-indigo-500/20 cursor-move hover:bg-indigo-500/40 transition-colors shadow-[0_0_15px_rgba(99,102,241,0.3)]"
            />
            {/* Rotation handle */}
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${sub.rotation}deg)` }}>
               <div 
                onMouseDown={startDrag('rotate-body', 'subject', sub.id)} 
                className="absolute top-0 left-1/2 -translate-x-1/2 w-4 h-4 bg-indigo-400 rounded-full cursor-pointer pointer-events-auto border-2 border-white/20 hover:scale-125 transition-transform" 
               />
            </div>
            <span className="absolute top-full mt-2 text-[8px] font-black uppercase text-indigo-400 whitespace-nowrap bg-black/60 px-1.5 py-0.5 rounded border border-indigo-500/20 pointer-events-none">
              {sub.label}
            </span>
          </div>
        </div>
      ))}

      {state.landmarks.map(lm => (
        <div key={lm.id} style={getPos(lm)} className="absolute -translate-x-1/2 translate-y-1/2 z-10">
          <div 
            onMouseDown={startDrag('move', 'landmark', lm.id)} 
            className="flex flex-col items-center cursor-move group"
          >
            <MapPin className="w-6 h-6 text-emerald-500/50 group-hover:text-emerald-400 transition-colors drop-shadow-lg" />
            <span className="text-[7px] font-black uppercase text-emerald-500 whitespace-nowrap bg-black/80 px-2 py-0.5 rounded border border-emerald-500/20 mt-0.5">
              {lm.label}
            </span>
          </div>
        </div>
      ))}

      {state.cameras.map((cam, idx) => (
        <div key={cam.id} style={getPos(cam)} className={`absolute -translate-x-1/2 translate-y-1/2 z-30 transition-opacity ${idx === state.activeCameraIndex ? 'scale-110' : 'opacity-40'}`}>
          <div 
            onMouseDown={startDrag('move', 'camera', idx)} 
            className="relative w-14 h-14 flex items-center justify-center cursor-move"
          >
            <Camera className="w-8 h-8 text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]" />
            <div className="absolute inset-0" style={{ transform: `rotate(${cam.rotation}deg)` }}>
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-3 h-3 bg-white rounded-full border-2 border-indigo-500" />
            </div>
          </div>
        </div>
      ))}

      {/* Origin Marker */}
      <div 
        className="absolute w-2 h-2 bg-white/5 rounded-full -translate-x-1/2 translate-y-1/2 pointer-events-none" 
        style={getPos({ x: 0, z: 0 })} 
      />
    </div>
  );
};

