                       <button onClick={() => { navigator.clipboard.writeText(state.draftPrompt); setCopying(true); setTimeout(() => setCopying(false), 2000); }} className="text-[10px] font-black uppercase text-indigo-400 flex items-center gap-2 hover:text-indigo-300 transition-colors bg-indigo-500/10 px-3 py-1.5 rounded-lg border border-indigo-500/20">
                         {copying ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />} {copying ? 'Copied' : 'Copy'}
                       </button>
                     </div>
                     <pre className="text-[10px] font-mono text-zinc-400 bg-black/40 p-4 rounded-xl border border-white/5 overflow-auto max-h-[400px] custom-scrollbar selection:bg-indigo-500/30">
                       {JSON.stringify(JSON.parse(state.draftPrompt), null, 2)}
                     </pre>
                   </div>
                </div>
                <div className="flex justify-center">
                  <button 
                    disabled={state.isGenerating}
                    onClick={async () => { 
                      setState(s => ({ ...s, isGenerating: true })); 
                      try {
                        const { url, cost } = await generateStudioImage(state, state.draftPrompt); 
                        setState(s => ({ 
                          ...s, 
                          generatedImage: url, 
                          isGenerating: false, 
                          isReviewingPrompt: false, 
                          isReviewingVideoPrompt: true, 
                          usage: { ...s.usage, totalSpent: s.usage.totalSpent + cost, render: s.usage.render + cost } 
                        })); 
                      } catch (e) {
                        alert("Generation failed. Please try a different lens or scale.");
                        setState(s => ({ ...s, isGenerating: false }));
                      }
                    }} 
                    className="bg-white text-black font-black px-12 py-6 rounded-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl group"
                  >
                    {state.isGenerating ? <Loader2 className="animate-spin" /> : <MonitorPlay className="group-hover:scale-110 transition-transform" />} 
                    <div className="text-left">
                      <div className="text-xl font-black uppercase">Commit Render</div>
                      <div className="text-[9px] font-bold text-black/40 uppercase tracking-widest">Cost: ₹{COST_PER_IMAGE.toFixed(2)}</div>
                    </div>
                  </button>
                </div>
             </div>
          </div>
        )}

        {(state.isReviewingVideoPrompt || state.isGeneratingVideo) && state.generatedImage && (
          <div className="absolute inset-0 z-[100] bg-[#050505]/95 backdrop-blur-3xl p-4 md:p-8 flex items-center justify-center">
            <button onClick={() => setState(s => ({ ...s, isReviewingVideoPrompt: false, isGeneratingVideo: false }))} className="absolute top-10 right-10 text-white/20 hover:text-white transition-colors p-2 rounded-full hover:bg-white/5"><X className="w-10 h-10" /></button>
            <div className="max-w-4xl w-full space-y-12 animate-in fade-in zoom-in duration-500">
               <div className="text-center space-y-2">
                 <h3 className="text-4xl md:text-6xl font-black italic tracking-tighter uppercase">Visual Review</h3>
                 <p className="text-indigo-400 text-[10px] font-black uppercase tracking-[0.6em] animate-pulse">Master Composition Confirmed</p>
               </div>

               <div className="relative rounded-[2rem] overflow-hidden border border-white/10 shadow-[0_0_100px_rgba(99,102,241,0.2)] aspect-video bg-black/40 group">
                 {state.generatedVideo ? (
                   <video src={state.generatedVideo} autoPlay loop muted playsInline className="w-full h-full object-cover" />
                 ) : (
                   <img src={state.generatedImage} className="w-full h-full object-cover" />
                 )}

                 {state.isGeneratingVideo && (
                   <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center gap-6">
                     <Loader2 className="w-16 h-16 text-indigo-500 animate-spin" />
                     <p className="text-white font-black tracking-widest uppercase text-sm">{state.videoStatus}</p>
                   </div>
                 )}
               </div>

               <div className="flex flex-col sm:flex-row gap-6 justify-center">
                 {!state.generatedVideo && !state.isGeneratingVideo && (
                    <button 
                      onClick={async () => {
                        setState(s => ({ ...s, isGeneratingVideo: true }));
                        try {
                          const { url, cost } = await generateStudioVideo(state, state.draftPrompt, state.generatedImage!, (s) => setState(prev => ({ ...prev, videoStatus: s })));
                          setState(s => ({ ...s, generatedVideo: url, isGeneratingVideo: false, usage: { ...s.usage, totalSpent: s.usage.totalSpent + cost, video: s.usage.video + cost } }));
                        } catch (e) {
                          alert("Video synthesis failed.");
                          setState(s => ({ ...s, isGeneratingVideo: false }));
                        }
                      }}
                      className="bg-indigo-600 text-white font-black px-12 py-6 rounded-2xl hover:bg-indigo-500 hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-xl"
                    >
                      <Play className="w-8 h-8" />
                      <div className="text-left">
                        <div className="text-xl font-black uppercase">Animate Seq.</div>
                        <div className="text-[9px] font-bold text-white/40 uppercase tracking-widest">Cost: ₹{COST_PER_VIDEO.toFixed(2)}</div>
                      </div>
                    </button>
                 )}

                 {(state.generatedImage || state.generatedVideo) && (
                   <a 
                    href={state.generatedVideo || state.generatedImage} 
                    download={`studio_render_${Date.now()}`}
                    className="bg-emerald-600 text-white font-black px-12 py-6 rounded-2xl hover:bg-emerald-500 hover:scale-105 transition-all flex items-center gap-4 shadow-xl"
                   >
                     <Download className="w-8 h-8" />
                     <div className="text-left">
                       <div className="text-xl font-black uppercase">Export Master</div>
                       <div className="text-[9px] font-bold text-white/40 uppercase tracking-widest">Download Asset</div>
                     </div>
                   </a>
                 )}
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Camera, Layers, Wand2, Loader2, X, Play, Download, 
  Target, MonitorPlay, Users, Landmark as LandmarkIcon, 
  Tv, Move, Sun, Copy, Check, Plus, Trash2, Edit3, MapPin, ScanSearch,
  Maximize, Minus, Search
} from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, CameraConfig, SubjectConfig, Landmark } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES, COST_PER_IMAGE, COST_PER_VIDEO } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import ShotScalePicker from './components/ShotScalePicker';
import LightRig from './components/LightRig';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo, analyzeBackground } from './services/geminiService';

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(window.innerWidth > 768);
  const [isViewfinderOpen, setIsViewfinderOpen] = useState(true);
  const [copying, setCopying] = useState(false);
  const [activeTab, setActiveTab] = useState<'talent' | 'scenery'>('talent');
  const [isAnalyzingBackground, setIsAnalyzingBackground] = useState(false);

  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: { positions: new Array(8).fill(false) },
    subjects: [{ id: 'sub-1', x: 0, z: 12, rotation: 180, gaze: 180, label: 'Protagonist' }],
    landmarks: [],
    cameras: [{
      id: 'cam-1', x: 0, z: 0, rotation: 0,
      model: CAMERA_MODELS[0], lens: LENSES[2].label, verticalAngle: VERTICAL_ANGLES[1],
    }],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 0.8,
    plannerOffset: { x: 0, z: -15 },
    usage: { totalSpent: 0, analysis: 0, render: 0, video: 0, tokens: 0 },
    inferredShotScale: undefined
  });

  const activeCamera = state.cameras[state.activeCameraIndex];

  const calculatedShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const sub = state.subjects[0] || { x: 0, z: 10 };
    const dx = sub.x - activeCamera.x;
    const dz = sub.z - activeCamera.z;
    const dist = Math.sqrt(dx*dx + dz*dz);
    const charHeightPercent = (6.0 / ((24 * dist) / mm)) * 100;

    if (charHeightPercent > 150) return "Extreme Close Up (ECU)";
    if (charHeightPercent > 70) return "Close Up (CU)";
    if (charHeightPercent > 40) return "Medium Shot (MS)";
    if (charHeightPercent > 20) return "Long Shot (LS)";
    return "Wide Shot (WS)";
  }, [activeCamera, state.subjects]);

  const updateSubject = (id: string, updates: Partial<SubjectConfig>) => {
    setState(s => ({
      ...s,
      subjects: s.subjects.map(sub => sub.id === id ? { ...sub, ...updates } : sub)
    }));
  };

  const updateLandmark = (id: string, updates: Partial<Landmark>) => {
    setState(s => ({
      ...s,
      landmarks: s.landmarks.map(lm => lm.id === id ? { ...lm, ...updates } : lm)
    }));
  };

  const handleAssetUpload = async (id: ReferenceType, url: string, mime: string) => {
    setState(s => ({
      ...s,
      references: { ...s.references, [id]: { ...s.references[id], dataUrl: url, mimeType: mime } }
    }));

    if (id === 'background') {
      setIsAnalyzingBackground(true);
      setActiveTab('scenery');
      try {
        const detected = await analyzeBackground(url);
        const newLandmarks: Landmark[] = detected.map((d, i) => ({
          id: `detected-${Date.now()}-${i}`,
          label: d.label || 'Feature',
          description: d.description || '',
          x: d.x ?? 0,
          z: d.z ?? 50
        }));
        setState(s => ({ ...s, landmarks: newLandmarks }));
      } catch (e) {
        console.error("Background analysis failed", e);
      } finally {
        setIsAnalyzingBackground(false);
      }
    }
  };

  const handleGeneratePrompt = async () => {
    setState(s => ({ ...s, isGeneratingPrompt: true }));
    try {
      const { script, cost, tokens } = await generateDraftPrompt({ ...state, inferredShotScale: state.inferredShotScale || calculatedShotScale });
      setState(s => ({ 
        ...s, 
        draftPrompt: script, 
        isGeneratingPrompt: false, 
        isReviewingPrompt: true, 
        usage: { 
          ...s.usage, 
          totalSpent: s.usage.totalSpent + cost,
          tokens: s.usage.tokens + tokens,
          analysis: s.usage.analysis + cost
        } 
      }));
    } catch (e) {
      alert("Synthesis engine error. Try again with fewer references.");
      setState(s => ({ ...s, isGeneratingPrompt: false }));
    }
  };

  const proseDisplay = useMemo(() => {
    try { return JSON.parse(state.draftPrompt).cinematic_prose || state.draftPrompt; } catch (e) { return state.draftPrompt; }
  }, [state.draftPrompt]);

  return (
    <div className="flex flex-col md:flex-row h-screen h-[100dvh] bg-[#050505] text-white overflow-hidden selection:bg-indigo-500/30">

      {/* Mobile Header */}
      <div className="md:hidden flex items-center justify-between p-4 bg-[#0d0d0d] border-b border-white/5 z-50">
        <div className="flex items-center gap-2">
          <LandmarkIcon className="w-5 h-5 text-indigo-500" />
          <h1 className="text-sm font-black tracking-tighter uppercase">Studio AI</h1>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsViewfinderOpen(!isViewfinderOpen)} 
            className={`p-2 rounded-lg border transition-all ${isViewfinderOpen ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-white/40'}`}
          >
            <MonitorPlay className="w-4 h-4" />
          </button>
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-2 bg-indigo-600 rounded-lg text-white"
          >
            <Layers className="w-4 h-4" />
          </button>
        </div>
      </div>

      <aside className={`
        fixed inset-0 md:relative z-[60] md:z-10
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        transition-transform duration-300 md:translate-x-0
        w-full md:w-[380px] lg:w-[420px] bg-[#0d0d0d] flex flex-col border-r border-white/5 shadow-2xl
      `}>
        <header className="p-5 md:p-6 border-b border-white/5 flex items-center justify-between bg-black/20">
          <div className="flex items-center gap-3">
            <LandmarkIcon className="w-6 h-6 md:w-7 md:h-7 text-indigo-500" />
            <h1 className="text-lg md:text-xl font-black tracking-tighter uppercase">Studio AI</h1>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-white/5 rounded-full text-white/40"><X /></button>
        </header>

        <div className="flex-1 overflow-y-auto p-5 md:p-6 space-y-8 custom-scrollbar">
          <div className="flex bg-white/5 p-1 rounded-xl gap-1 ring-1 ring-white/5">
            <button onClick={() => setActiveTab('talent')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'talent' ? 'bg-indigo-600 shadow-lg text-white' : 'hover:bg-white/5 text-white/40'}`}>Talent</button>
            <button onClick={() => setActiveTab('scenery')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'scenery' ? 'bg-indigo-600 shadow-lg text-white' : 'hover:bg-white/5 text-white/40'}`}>Scenery</button>
          </div>

          {activeTab === 'talent' ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2">
                  <Users className="w-3 h-3" /> Production Cast
                </h2>
                <button 
                  onClick={() => setState(s => ({ ...s, subjects: [...s.subjects, { id: `sub-${Date.now()}`, x: (Math.random()-0.5)*10, z: 15, rotation: 180, gaze: 180, label: `Extra ${s.subjects.length}` }] }))} 
                  className="p-1.5 bg-indigo-600 rounded-lg hover:scale-110 transition-transform shadow-lg"
                >
                  <Plus className="w-4 h-4" />
                </button>
              </div>
              <div className="space-y-4">
                {state.subjects.map((sub) => (
                  <div key={sub.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-4 shadow-inner group">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3 flex-1">
                        <div className="w-2 h-2 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
                        <input 
                          value={sub.label} 
                          onChange={(e) => updateSubject(sub.id, { label: e.target.value })} 
                          className="bg-transparent text-xs font-bold focus:outline-none focus:text-indigo-400 w-full" 
                        />
                      </div>
                      <button 
                        onClick={() => setState(s => ({ ...s, subjects: s.subjects.filter(x => x.id !== sub.id) }))} 
                        className="text-white/10 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 p-1"
                      >
                        <Trash2 className="w-3 h-3" />
                      </button>
                    </div>
                    <OrientationSlider config={sub} activeCamera={activeCamera} onChange={(v) => updateSubject(sub.id, { rotation: v })} />
                    <GazeSelector subjectId="a" config={sub} activeCamera={activeCamera} onChange={(v) => updateSubject(sub.id, { gaze: v })} />
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2">
                  <MapPin className="w-3 h-3" /> Environmental Anchors
                </h2>
                <button 
                  onClick={() => setState(s => ({ ...s, landmarks: [...s.landmarks, { id: `lm-${Date.now()}`, label: 'New Landmark', description: 'Background feature...', x: (Math.random()-0.5)*40, z: 60 }] }))} 
                  className="p-1.5 bg-emerald-600 rounded-lg hover:scale-110 transition-transform shadow-lg"
                >
                  <Plus className="w-4 h-4" />
                </button>
              </div>

              {isAnalyzingBackground && (
                <div className="bg-emerald-500/10 border border-emerald-500/20 p-4 rounded-2xl flex items-center gap-4 animate-pulse">
                  <ScanSearch className="w-5 h-5 text-emerald-500 animate-bounce" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-emerald-400">Scanning environment...</p>
                </div>
              )}

              <div className="space-y-4">
                {state.landmarks.map(lm => (
                  <div key={lm.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-3 shadow-inner group">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2 flex-1">
                        <MapPin className="w-3 h-3 text-emerald-500" />
                        <input value={lm.label} onChange={(e) => updateLandmark(lm.id, { label: e.target.value })} className="bg-transparent text-xs font-bold focus:outline-none focus:text-emerald-400 w-full" />
                      </div>
                      <button onClick={() => setState(s => ({ ...s, landmarks: s.landmarks.filter(x => x.id !== lm.id) }))} className="text-white/10 hover:text-red-500 opacity-0 group-hover:opacity-100 p-1"><Trash2 className="w-3 h-3" /></button>
                    </div>
                    <textarea 
                      value={lm.description} 
                      onChange={(e) => updateLandmark(lm.id, { description: e.target.value })} 
                      className="w-full bg-black/40 border border-white/5 rounded-lg p-2 text-[10px] text-white/60 focus:outline-none min-h-[60px] custom-scrollbar focus:border-emerald-500/20" 
                      placeholder="Describe feature..." 
                    />
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="space-y-4">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2">
              <Layers className="w-3 h-3" /> Material References
            </h2>
            <div className="grid grid-cols-3 gap-2.5">
              {REFERENCE_SLOTS.map(slot => (
                <ReferenceUploader 
                  key={slot.id} 
                  slot={slot} 
                  dataUrl={state.references[slot.id].dataUrl} 
                  onUpload={(url, mime) => handleAssetUpload(slot.id, url, mime)} 
                  onRemove={() => setState(s => ({ ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: undefined } } }))} 
                />
              ))}
            </div>
          </div>

          <section className="bg-white/5 p-4 md:p-5 rounded-2xl border border-white/10 space-y-5">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
               <Camera className="w-3 h-3" /> Camera Settings
            </h2>
            <div className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[8px] font-bold text-white/30 uppercase ml-1">Lens System</label>
                <select 
                  value={activeCamera.lens}
                  onChange={(e) => {
                    const n = [...state.cameras];
                    n[state.activeCameraIndex] = { ...n[state.activeCameraIndex], lens: e.target.value };
                    setState(s => ({ ...s, cameras: n }));
                  }}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-3 py-2.5 text-[11px] font-bold focus:ring-2 focus:ring-indigo-500/50 outline-none appearance-none"
                >
                  {LENSES.map(l => <option key={l.label} value={l.label}>{l.label}</option>)}
                </select>
              </div>
              <ShotScalePicker 
                value={state.inferredShotScale || calculatedShotScale} 
                onChange={(val) => setState(s => ({ ...s, inferredShotScale: val }))} 
              />
            </div>
          </section>

          <section className="space-y-4 pb-10">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Sun className="w-3 h-3" /> Production Lighting
            </h2>
            <div className="bg-black/40 p-5 rounded-2xl border border-white/5 shadow-inner">
              <LightRig 
                activePositions={state.lighting.positions} 
                onToggle={(idx) => setState(s => {
                  const np = [...s.lighting.positions];
                  np[idx] = !np[idx];
                  return { ...s, lighting: { ...s.lighting, positions: np } };
                })}
                orientation={state.subjects[0]?.rotation || 180}
              />
            </div>
          </section>
        </div>

        <footer className="p-6 border-t border-white/5 bg-black/40 backdrop-blur-xl">
          <button 
            onClick={handleGeneratePrompt} 
            disabled={state.isGeneratingPrompt} 
            className="w-full bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 py-4 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-indigo-500/20 transition-all active:scale-[0.98] group"
          >
            {state.isGeneratingPrompt ? <Loader2 className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5 group-hover:rotate-12 transition-transform" />}
            <span className="font-black text-sm uppercase tracking-widest">Execute Scripting</span>
          </button>
        </footer>
      </aside>

      <main className="flex-1 flex flex-col relative bg-[#050505] min-h-0">
        <div className="flex-1 p-3 md:p-8 flex flex-col min-h-0 overflow-hidden relative">
          <div className="flex-1 min-h-0 border border-white/5 md:rounded-[2.5rem] bg-[#080808] relative overflow-hidden shadow-2xl flex flex-col rounded-2xl">
            <FloorPlanner 
              state={state} 
              onUpdateSubject={updateSubject} 
              onUpdateLandmark={updateLandmark}
              onUpdateCamera={(idx, updates) => setState(s => { const n = [...s.cameras]; n[idx] = { ...n[idx], ...updates }; return { ...s, cameras: n }; })} 
              onUpdatePlanner={(u) => setState(s => ({ ...s, ...u }))} 
              onSelectCamera={(idx) => setState(s => ({ ...s, activeCameraIndex: idx }))} 
            />

            {isViewfinderOpen && (
              <div className="absolute top-3 right-3 md:top-6 md:right-6 w-44 sm:w-80 z-40 animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none">
                <div className="bg-black/80 p-1 rounded-xl md:rounded-2xl border border-white/20 backdrop-blur-2xl shadow-2xl ring-1 ring-black/50 overflow-hidden pointer-events-auto">
                  <CameraViewfinder state={state} inferredScale={state.inferredShotScale || calculatedShotScale} />
                </div>
              </div>
            )}

            {/* Viewport Control Cluster */}
            <div className="absolute bottom-4 left-4 md:bottom-8 md:left-8 flex flex-col gap-2 pointer-events-none">
              <div className="bg-black/60 backdrop-blur-md border border-white/10 rounded-2xl p-2 flex flex-col gap-2 shadow-2xl pointer-events-auto">
                <button 
                  onClick={() => setState(s => ({ ...s, plannerZoom: Math.min(5, s.plannerZoom * 1.3) }))}
                  className="p-3 hover:bg-white/10 rounded-xl text-white/60 hover:text-white transition-all active:scale-90"
                  title="Zoom In"
                >
                  <Search className="w-5 h-5" />
                </button>
                <div className="h-px bg-white/10 mx-2" />
                <button 
                  onClick={() => setState(s => ({ ...s, plannerZoom: Math.max(0.1, s.plannerZoom / 1.3) }))}
                  className="p-3 hover:bg-white/10 rounded-xl text-white/60 hover:text-white transition-all active:scale-90"
                  title="Zoom Out"
                >
                  <Minus className="w-5 h-5" />
                </button>
