import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, SubjectConfig, Landmark, ReferenceType } from "../types";

export const COST_PER_IMAGE = 2.50;
export const COST_PER_VIDEO = 12.60;
export const COST_PER_1K_TOKENS = 0.0084;

async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.7): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const analyzeBackground = async (dataUrl: string): Promise<Partial<Landmark>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const { data, mimeType } = await downscaleImage(dataUrl, 1024, 0.8);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data, mimeType } },
        { text: "Identify key background landmarks and features in this image. Provide labels, descriptions, and relative 3D positions (X: -30 to 30, Z: 20 to 100)." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            label: { type: Type.STRING },
            description: { type: Type.STRING },
            x: { type: Type.NUMBER },
            z: { type: Type.NUMBER }
          },
          required: ["label", "description", "x", "z"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [];
  }
};

const getFovAngle = (lens: string) => {
  const focalLength = parseInt(lens.match(/(\d+)mm/)?.[1] || "50");
  return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
};

const filterVisibleLandmarks = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const fov = getFovAngle(cam.lens);
  const rotRad = -cam.rotation * (Math.PI / 180);

  return state.landmarks.filter(lm => {
    const dx = lm.x - cam.x;
    const dz = lm.z - cam.z;
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);
    if (localZ <= 0.5) return false;
    const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
    const angleToLm = Math.abs(Math.atan2(localX, localZ) * (180 / Math.PI));
    return angleToLm < (fov / 2) + 15; 
  }).map(lm => ({
    label: lm.label,
    depth: Math.sqrt((lm.x - cam.x)**2 + (lm.z - cam.z)**2).toFixed(1) + "ft",
    description: lm.description
  }));
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const visibleLandmarks = filterVisibleLandmarks(state);
  const shotScale = state.inferredShotScale || "Medium Shot (MS)";

  const parts: any[] = [];

  // 1. Process Global References
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({ text: `GLOBAL_REF_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {}
    }
  }

  // 2. Process Per-Subject References
  for (const subject of state.subjects) {
    const subLabel = subject.label.replace(/\s+/g, '_').toUpperCase();
    for (const type of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = subject.references[type];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
          parts.push({ text: `SUBJECT_${subLabel}_${type.toUpperCase()}:` });
          parts.push({ inlineData: { data, mimeType } });
        } catch (e) {}
      }
    }
  }

  const compositionGuide = `
=== PRODUCTION_METADATA ===
SHOT_SCALE: ${shotScale}
LENS: ${activeCamera.lens}
ELEVATION: ${activeCamera.verticalAngle}
VISIBLE_LANDMARKS: ${JSON.stringify(visibleLandmarks)}
SUBJECTS_LAYOUT: ${JSON.stringify(state.subjects.map(s => ({ 
    label: s.label, 
    pos: { x: s.x.toFixed(1), z: s.z.toFixed(1) }, 
    orientation: s.rotation, 
    gaze: s.gaze 
})))}
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: compositionGuide },
        { text: "Synthesize a professional JSON specification. Weave subject references, lighting, and landmarks into 'cinematic_prose'." }
      ] 
    },
    config: { 
      systemInstruction: "You are a Virtual Production Architect. Use the provided SUBJECT_[NAME] references to describe specific characters. Output valid JSON.", 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          environmental_anchors: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: { label: { type: Type.STRING }, depth: { type: Type.STRING }, description: { type: Type.STRING } }
            }
          },
          technical_spec: {
            type: Type.OBJECT,
            properties: { lens: { type: Type.STRING }, shot_scale: { type: Type.STRING } }
          }
        },
        required: ["cinematic_prose", "environmental_anchors"]
      }
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 2000;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let cinematic_prose = draftJson;
  try { cinematic_prose = JSON.parse(draftJson).cinematic_prose || draftJson; } catch (e) {}

  const parts: any[] = [];

  // Global Refs
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `GLOBAL_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  // Subject Refs
  for (const subject of state.subjects) {
    const subLabel = subject.label.replace(/\s+/g, '_').toUpperCase();
    for (const type of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = subject.references[type];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
        parts.push({ text: `SUBJECT_${subLabel}_${type.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }
  }

  parts.push({ text: `NARRATIVE: ${cinematic_prose}\nLIGHTING: ${JSON.stringify(state.lighting.positions)}` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9", imageSize: "1K" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed.");
  return { url: `data:image/png;base64,${imgPart.inlineData.data}`, cost: COST_PER_IMAGE };
};

export const generateStudioVideo = async (state: StudioState, script: string, baseImage: string, onStatusChange: (s: string) => void): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Preparing Video Synthesis...");
  const base64Data = baseImage.split(',')[1];
  let prose = script;
  try { prose = JSON.parse(script).cinematic_prose || script; } catch(e) {}

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic animation: ${prose}`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Processing Motion Vectors...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return { url: URL.createObjectURL(blob), cost: COST_PER_VIDEO };
};

import { Camera, MapPin, Eye } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig, Landmark } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: string, updates: Partial<SubjectConfig>) => void;
  onUpdateLandmark: (id: string, updates: Partial<Landmark>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onUpdatePlanner: (updates: { zoom?: number; offset?: { x: number; z: number } }) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state, onUpdateSubject, onUpdateLandmark, onUpdateCamera, onUpdatePlanner, onSelectCamera 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  // Single state to manage both mouse and touch drags for consistency
  const [activeDrag, setActiveDrag] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'pan' | 'pinch'; 
    target: 'subject' | 'camera' | 'landmark' | 'background';
    id: any;
    startX: number;
    startY: number;
    initialOffset: { x: number; z: number };
    initialDist?: number;
    initialZoom?: number;
  } | null>(null);

  const getRange = useCallback(() => 50 / state.plannerZoom, [state.plannerZoom]);

  const handleStart = (type: 'move' | 'rotate-body' | 'rotate-gaze' | 'pan', target: any, id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();

    // Check for middle mouse pan
    const isMiddleMouse = 'button' in e && (e as React.MouseEvent).button === 1;
    const finalType = isMiddleMouse ? 'pan' : type;
    const finalTarget = isMiddleMouse ? 'background' : target;

    const clientX = 'clientX' in e ? e.clientX : e.touches[0].clientX;
    const clientY = 'clientY' in e ? e.clientY : e.touches[0].clientY;

    if (finalTarget === 'camera' && finalType === 'move') onSelectCamera(id);

    // If pinch (2 fingers)
    if ('touches' in e && e.touches.length === 2) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      setActiveDrag({
        type: 'pinch',
        target: 'background',
        id: null,
        startX: clientX,
        startY: clientY,
        initialOffset: { ...state.plannerOffset },
        initialDist: dist,
        initialZoom: state.plannerZoom
      });
      return;
    }

    setActiveDrag({ 
      type: finalType, 
      target: finalTarget, 
      id, 
      startX: clientX, 
      startY: clientY, 
      initialOffset: { ...state.plannerOffset } 
    });
  };

  const handleMove = useCallback((clientX: number, clientY: number, touchCount: number) => {
    if (!activeDrag || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const range = getRange();

    // 1. Panning Logic
    if (activeDrag.type === 'pan' && touchCount === 1) {
      const dx = (clientX - activeDrag.startX) / rect.width * (range * 2);
      const dz = -(clientY - activeDrag.startY) / rect.height * (range * 2);
      onUpdatePlanner({ offset: { x: activeDrag.initialOffset.x + dx, z: activeDrag.initialOffset.z + dz } });
      return;
    }

    // 2. Movement Logic
    const coordX = ((clientX - rect.left) / rect.width - 0.5) * (range * 2) - state.plannerOffset.x;
    const coordZ = (1 - (clientY - rect.top) / rect.height - 0.5) * (range * 2) - state.plannerOffset.z;

    if (activeDrag.type === 'move') {
      if (activeDrag.target === 'subject') onUpdateSubject(activeDrag.id, { x: coordX, z: coordZ });
      else if (activeDrag.target === 'camera') onUpdateCamera(activeDrag.id, { x: coordX, z: coordZ });
      else if (activeDrag.target === 'landmark') onUpdateLandmark(activeDrag.id, { x: coordX, z: coordZ });
      return;
    }

    // 3. Rotation Logic (Body and Gaze)
    if (activeDrag.type === 'rotate-body' || activeDrag.type === 'rotate-gaze') {
      const targetObj: any = activeDrag.target === 'subject' 
        ? state.subjects.find(s => s.id === activeDrag.id) 
        : state.cameras[activeDrag.id];

      if (!targetObj) return;

      const objScreenX = rect.left + rect.width * (0.5 + (targetObj.x + state.plannerOffset.x) / (range * 2));
      const objScreenY = rect.top + rect.height * (0.5 - (targetObj.z + state.plannerOffset.z) / (range * 2));

      let angle = (Math.atan2(clientX - objScreenX, -(clientY - objScreenY)) * 180 / Math.PI + 360) % 360;

      if (activeDrag.type === 'rotate-body') onUpdateSubject(activeDrag.id, { rotation: angle });
      else if (activeDrag.type === 'rotate-gaze') onUpdateSubject(activeDrag.id, { gaze: angle });
    }
  }, [activeDrag, state.plannerOffset, state.subjects, state.cameras, getRange, onUpdatePlanner, onUpdateSubject, onUpdateCamera, onUpdateLandmark]);

  const handlePinch = (e: TouchEvent) => {
    if (activeDrag?.type === 'pinch' && e.touches.length === 2) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      const scale = dist / (activeDrag.initialDist || 1);
      const newZoom = (activeDrag.initialZoom || 1) * scale;
      const clampedZoom = Math.max(0.1, Math.min(5, newZoom));
      onUpdatePlanner({ zoom: clampedZoom });
    }
  };

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => handleMove(e.clientX, e.clientY, 1);
    const onTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2) handlePinch(e);
      else handleMove(e.touches[0].clientX, e.touches[0].clientY, 1);
    };
    const onEnd = () => setActiveDrag(null);

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onEnd);
    window.addEventListener('touchmove', onTouchMove, { passive: false });
    window.addEventListener('touchend', onEnd);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', onEnd);
    };
  }, [handleMove, activeDrag]);

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const zoomFactor = 1.15;
    const newZoom = e.deltaY > 0 ? state.plannerZoom / zoomFactor : state.plannerZoom * zoomFactor;
    onUpdatePlanner({ zoom: Math.max(0.1, Math.min(5, newZoom)) });
  };

  const getPos = (obj: { x: number, z: number }) => {
    const range = getRange();
    const leftVal = (((obj.x + state.plannerOffset.x) / (range * 2)) + 0.5) * 100;
    const bottomVal = (((obj.z + state.plannerOffset.z) / (range * 2)) + 0.5) * 100;
    return { left: `${leftVal}%`, bottom: `${bottomVal}%` };
  };

  return (
    <div 
      ref={containerRef} 
      onMouseDown={handleStart('pan', 'background', null)} 
      onTouchStart={handleStart('pan', 'background', null)}
      onWheel={handleWheel}
      className="w-full h-full relative overflow-hidden bg-[#050505] cursor-grab active:cursor-grabbing touch-none select-none"
    >
      {/* Dynamic Grid */}
      <div 
        className="absolute inset-0 opacity-10 pointer-events-none transition-all duration-75" 
        style={{ 
          backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
          backgroundSize: `${20 * state.plannerZoom}px ${20 * state.plannerZoom}px`, 
          backgroundPosition: `${(state.plannerOffset.x * 10 * state.plannerZoom) + (containerRef.current?.offsetWidth || 0) / 2}px ${(-state.plannerOffset.z * 10 * state.plannerZoom) + (containerRef.current?.offsetHeight || 0) / 2}px` 
        }} 
      />

      {state.subjects.map(sub => (
        <div key={sub.id} style={getPos(sub)} className="absolute -translate-x-1/2 translate-y-1/2 z-20 transition-[left,bottom] duration-75 ease-out">
          <div className="relative w-16 h-16 md:w-20 md:h-20 flex items-center justify-center">
            {/* Body Movement Handle */}
            <div 
              onMouseDown={handleStart('move', 'subject', sub.id)} 
              onTouchStart={handleStart('move', 'subject', sub.id)}
              className="absolute inset-4 rounded-full border-2 border-indigo-500 bg-indigo-500/20 cursor-move hover:bg-indigo-500/40 transition-colors shadow-xl ring-1 ring-white/10"
            />

            {/* Body Rotation Handle (Indigo) */}
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${sub.rotation}deg)` }}>
               <div 
                onMouseDown={handleStart('rotate-body', 'subject', sub.id)} 
                onTouchStart={handleStart('rotate-body', 'subject', sub.id)}
                className="absolute top-0 left-1/2 -translate-x-1/2 w-6 h-6 flex items-center justify-center cursor-pointer pointer-events-auto group"
               >
                 <div className="w-3 h-3 md:w-4 md:h-4 bg-indigo-400 rounded-full border-2 border-white shadow-lg group-hover:scale-125 transition-transform" />
               </div>
            </div>

            {/* Gaze Rotation Handle (Emerald) */}
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${sub.gaze}deg)` }}>
               <div 
                onMouseDown={handleStart('rotate-gaze', 'subject', sub.id)} 
                onTouchStart={handleStart('rotate-gaze', 'subject', sub.id)}
                className="absolute top-2 left-1/2 -translate-x-1/2 w-6 h-6 flex items-center justify-center cursor-pointer pointer-events-auto group"
               >
                 <Eye className="w-4 h-4 md:w-5 md:h-5 text-emerald-400 drop-shadow-lg group-hover:scale-125 transition-transform" />
               </div>
            </div>

            <span className="absolute top-full mt-4 text-[7px] md:text-[9px] font-black uppercase text-indigo-400 whitespace-nowrap bg-black/80 px-2 py-1 rounded border border-indigo-500/30 backdrop-blur-md pointer-events-none shadow-xl">
              {sub.label}
            </span>
          </div>
        </div>
      ))}

      {state.landmarks.map(lm => (
        <div key={lm.id} style={getPos(lm)} className="absolute -translate-x-1/2 translate-y-1/2 z-10 transition-[left,bottom] duration-75 ease-out">
          <div 
            onMouseDown={handleStart('move', 'landmark', lm.id)} 
            onTouchStart={handleStart('move', 'landmark', lm.id)}
            className="flex flex-col items-center cursor-move group p-2"
          >
            <MapPin className="w-6 h-6 md:w-8 md:h-8 text-emerald-500/60 group-hover:text-emerald-400 transition-colors drop-shadow-xl" />
            <span className="text-[7px] font-black uppercase text-emerald-500 whitespace-nowrap bg-black/80 px-2 py-1 rounded border border-emerald-500/30 mt-1 backdrop-blur-md">
              {lm.label}
            </span>
          </div>
        </div>
      ))}

      {state.cameras.map((cam, idx) => (
        <div key={cam.id} style={getPos(cam)} className={`absolute -translate-x-1/2 translate-y-1/2 z-30 transition-all ${idx === state.activeCameraIndex ? 'scale-110' : 'opacity-40 grayscale'}`}>
          <div 
            onMouseDown={handleStart('move', 'camera', idx)} 
            onTouchStart={handleStart('move', 'camera', idx)}
            className="relative w-14 h-14 md:w-16 md:h-16 flex items-center justify-center cursor-move"
          >
            <div className="bg-white/10 p-2 md:p-3 rounded-2xl border border-white/20 backdrop-blur-xl shadow-2xl">
              <Camera className="w-6 h-6 md:w-8 md:h-8 text-white" />
            </div>
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${cam.rotation}deg)` }}>
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-4 h-4 bg-white rounded-full border-2 border-indigo-500 shadow-xl" />
            </div>
          </div>
        </div>
      ))}

      {/* World Origin */}
      <div className="absolute w-10 h-10 border border-white/5 rounded-full -translate-x-1/2 translate-y-1/2 pointer-events-none flex items-center justify-center" style={getPos({ x: 0, z: 0 })}>
        <div className="w-1 h-1 bg-white/20 rounded-full" />
      </div>
    </div>
  );
};

export default FloorPlanner;

import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, SubjectConfig, Landmark, ReferenceType } from "../types";

export const COST_PER_IMAGE = 2.50;
export const COST_PER_VIDEO = 12.60;
export const COST_PER_1K_TOKENS = 0.0084;

async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.7): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const analyzeBackground = async (dataUrl: string): Promise<Partial<Landmark>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const { data, mimeType } = await downscaleImage(dataUrl, 1024, 0.8);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data, mimeType } },
        { text: "Identify key background landmarks and features in this image. Provide labels, descriptions, and relative 3D positions (X: -30 to 30, Z: 20 to 100)." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            label: { type: Type.STRING },
            description: { type: Type.STRING },
            x: { type: Type.NUMBER },
            z: { type: Type.NUMBER }
          },
          required: ["label", "description", "x", "z"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [];
  }
};

const getFovAngle = (lens: string) => {
  const focalLength = parseInt(lens.match(/(\d+)mm/)?.[1] || "50");
  return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
};

const filterVisibleLandmarks = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const fov = getFovAngle(cam.lens);

  return state.landmarks.filter(lm => {
    const dx = lm.x - cam.x;
    const dz = lm.z - cam.z;
    const dist = Math.sqrt(dx*dx + dz*dz);
    if (dist <= 0.5) return false;

    const angleToLmGlobal = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
    let relAngle = (angleToLmGlobal - cam.rotation + 540) % 360 - 180;

    return Math.abs(relAngle) < (fov / 2) + 15; 
  }).map(lm => ({
    label: lm.label,
    depth: Math.sqrt((lm.x - cam.x)**2 + (lm.z - cam.z)**2).toFixed(1) + "ft",
    description: lm.description
  }));
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const visibleLandmarks = filterVisibleLandmarks(state);
  const shotScale = state.inferredShotScale || "Medium Shot (MS)";

  const parts: any[] = [];

  // Global References
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({ text: `GLOBAL_REF_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      } catch (e) {}
    }
  }

  // Per-Subject References
  for (const subject of state.subjects) {
    const subLabel = subject.label.replace(/\s+/g, '_').toUpperCase();
    for (const type of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = subject.references[type];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
          parts.push({ text: `SUBJECT_${subLabel}_${type.toUpperCase()}:` }, { inlineData: { data, mimeType } });
        } catch (e) {}
      }
    }
  }

  const compositionGuide = `
=== MACHINE_TAGS ===
COORDINATE_SYSTEM: 0deg=NORTH (Depth+), 90deg=EAST (Right+), 180deg=SOUTH (Depth-), 270deg=WEST (Right-)
SHOT_SCALE: ${shotScale}
CAMERA_POS: {x: ${activeCamera.x.toFixed(1)}, z: ${activeCamera.z.toFixed(1)}}
CAMERA_ROTATION: ${activeCamera.rotation.toFixed(1)}deg
VISIBLE_LANDMARKS: ${JSON.stringify(visibleLandmarks)}
SUBJECTS: ${JSON.stringify(state.subjects.map(s => ({ 
    label: s.label, 
    pos: { x: s.x.toFixed(1), z: s.z.toFixed(1) }, 
    torso_orientation: s.rotation, 
    gaze_rotation: s.gaze 
})))}
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: compositionGuide },
        { text: "Synthesize a professional JSON specification. Interpret the degrees relative to the camera position. Use the provided SUBJECT references for high-fidelity character rendering." }
      ] 
    },
    config: { 
      systemInstruction: "You are a Virtual Production Render Engine. Interpret spatial tags literally: 0° is North (Z+). If a subject has a torso_orientation of 0° and the camera is at Z=0 looking North, the subject is facing AWAY from the camera. If torso_orientation is 180°, they face the camera. Output JSON.", 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          technical_spec: {
            type: Type.OBJECT,
            properties: { lens: { type: Type.STRING }, shot_scale: { type: Type.STRING } }
          }
        },
        required: ["cinematic_prose"]
      }
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 2000;
