};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let cinematic_prose = draftJson;
  try { cinematic_prose = JSON.parse(draftJson).cinematic_prose || draftJson; } catch (e) {}

  const parts: any[] = [];

  // Add all relevant references with labels
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `REFERENCE_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  for (const subject of state.subjects) {
    const subLabel = subject.label.replace(/\s+/g, '_').toUpperCase();
    for (const type of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = subject.references[type];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
        parts.push({ text: `SUBJECT_${subLabel}_${type.toUpperCase()}_REFERENCE:` }, { inlineData: { data, mimeType } });
      }
    }
  }

  parts.push({ text: `NARRATIVE: ${cinematic_prose}\nCOORD_DATA: 0deg=North, 90deg=East. Lighting follows specified orientation.` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9", imageSize: "1K" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed.");
  return { url: `data:image/png;base64,${imgPart.inlineData.data}`, cost: COST_PER_IMAGE };
};

