    const angleToSub = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
    let relAngle = (angleToSub - cam.rotation + 540) % 360 - 180;
    const side = relAngle < 0 ? "CAMERA_LEFT" : "CAMERA_RIGHT";
