SUBJECTS: ${JSON.stringify(subjectTags)}
ENVIRONMENT: ${JSON.stringify(state.landmarks)}
SHOT_SCALE: ${state.inferredShotScale || "Medium Shot"}
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [...parts, { text: compositionGuide + "\n\nSynthesize a professional cinematic spec based on these tags and references." }] 
    },
    config: { 
      systemInstruction: "You are a virtual production director. Output valid JSON containing 'cinematic_prose'. Respect the MACHINE_TAGS strictly.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          technical_spec: { type: Type.OBJECT, properties: { shot_scale: { type: Type.STRING } } }
        },
        required: ["cinematic_prose"]
      }
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 1500;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

