};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cam = state.cameras[state.activeCameraIndex];

  const parts: any[] = [];

  // 1. Global Scene References
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    if (state.references[key]?.dataUrl) {
      const { data, mimeType } = await downscaleImage(state.references[key].dataUrl!, 256, 0.4);
      parts.push({ text: `REFERENCE_GLOBAL_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  // 2. Subject Specific References (Face, Costume, Pose)
  const subjectTags = [];
  for (const sub of state.subjects) {
    const dx = sub.x - cam.x;
    const dz = sub.z - cam.z;
    const angleToSub = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
    let relAngle = (angleToSub - cam.rotation + 540) % 360 - 180;
    const side = relAngle < 0 ? "CAMERA_LEFT" : "CAMERA_RIGHT";

    // Add visual references for this subject
    for (const refKey of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = sub.references[refKey];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({ text: `REFERENCE_SUBJECT_${sub.id.toUpperCase()}_${refKey.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }

    subjectTags.push({
      id: sub.id,
      label: sub.label,
      world_pos: { x: sub.x, z: sub.z },
      body_rotation: sub.rotation,
      gaze_rotation: sub.gaze,
      camera_relative_side: side,
      has_character_ref: !!sub.references.character?.dataUrl,
      has_costume_ref: !!sub.references.costume?.dataUrl,
      has_pose_ref: !!sub.references.pose?.dataUrl
    });
  }

  const compositionGuide = `
=== MACHINE_TAGS ===
COORD_SYS: 0deg=North(+Z), 90deg=East(+X), 180deg=South(-Z), 270deg=West(-X)
CAMERA: pos(${cam.x.toFixed(1)}, ${cam.z.toFixed(1)}), rotation(${cam.rotation.toFixed(1)}deg), lens(${cam.lens})
SHOT_SCALE: ${state.inferredShotScale || "Medium Shot"}

ENVIRONMENT_LANDMARKS: ${JSON.stringify(state.landmarks.map(lm => ({ label: lm.label, desc: lm.description, pos: { x: lm.x, z: lm.z } })))}

SUBJECT_SPECIFICATIONS:
${JSON.stringify(subjectTags, null, 2)}

INSTRUCTIONS: 
1. Reconcile the character face, costume, and pose references for each subject.
2. Build the environment based on the provided landmark descriptions and background reference.
3. Obey the 0-360 deg world rotation for all subjects.
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [...parts, { text: compositionGuide + "\n\nSynthesize a professional cinematic spec based on these tags and references." }] 
    },
    config: { 
      systemInstruction: "You are a professional Virtual Production Director. Your output MUST be a JSON object with a 'cinematic_prose' field. This field should be a high-fidelity, descriptive prompt that exactly matches the provided reference images and spatial tags.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cinematic_prose: { type: Type.STRING },
          technical_spec: { type: Type.OBJECT, properties: { shot_scale: { type: Type.STRING } } }
        },
        required: ["cinematic_prose"]
      }
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 2000;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let prose = draftJson;
  try { prose = JSON.parse(draftJson).cinematic_prose || draftJson; } catch (e) {}

  const parts: any[] = [];

  // Final render passes all references again for the Pro model
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    if (state.references[key]?.dataUrl) {
      const { data, mimeType } = await downscaleImage(state.references[key].dataUrl!, 512, 0.6);
      parts.push({ text: `RENDER_REF_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  for (const sub of state.subjects) {
    for (const refKey of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = sub.references[refKey];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.6);
        parts.push({ text: `RENDER_SUB_${sub.id.toUpperCase()}_${refKey.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }
  }

  parts.push({ text: `FINAL_SCENE_INSTRUCTION: ${prose}\n\nStrictly adhere to subject identity and spatial coordinates (0deg=North).` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9", imageSize: "1K" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Render Failed");
  return { url: `data:image/png;base64,${imgPart.inlineData.data}`, cost: COST_PER_IMAGE };
};

