export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cam = state.cameras[state.activeCameraIndex];
  const focalLength = LENSES.find(l => l.label === cam.lens)?.mm || 50;

  const parts: any[] = [];

  // 1. Global Scene References
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    if (state.references[key]?.dataUrl) {
      const { data, mimeType } = await downscaleImage(state.references[key].dataUrl!, 256, 0.4);
      parts.push({ text: `REFERENCE_GLOBAL_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  // 2. Subject Specific References with explicit screen percentage calculation
  const subjectTags = [];
  for (const sub of state.subjects) {
    const dx = sub.x - cam.x;
    const dz = sub.z - cam.z;
    const dist = Math.sqrt(dx*dx + dz*dz);

    // Calculate vertical frame height at distance Z
    // FrameHeight = (SensorHeight * Distance) / FocalLength
    // We assume 35mm full frame sensor height (24mm)
    const frameHeightAtDist = (24 * dist) / focalLength;
    const subjectRealHeight = 6.0; // Average human height in feet
    const screenPercentage = (subjectRealHeight / frameHeightAtDist) * 100;

    const angleToSub = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
    let relAngle = (angleToSub - cam.rotation + 540) % 360 - 180;
    const side = relAngle < 0 ? "CAMERA_LEFT" : "CAMERA_RIGHT";

    // Add visual references for this subject
    for (const refKey of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = sub.references[refKey];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({ text: `REFERENCE_SUBJECT_${sub.id.toUpperCase()}_${refKey.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }

    subjectTags.push({
      id: sub.id,
      label: sub.label,
      screen_size_percentage: `${screenPercentage.toFixed(1)}%`,
      world_pos: { x: sub.x.toFixed(1), z: sub.z.toFixed(1) },
      body_rotation: `${sub.rotation.toFixed(0)}deg`,
      gaze_rotation: `${sub.gaze.toFixed(0)}deg`,
      frame_position: side,
      visual_assets: {
        character: !!sub.references.character?.dataUrl,
        costume: !!sub.references.costume?.dataUrl,
        pose: !!sub.references.pose?.dataUrl
      }
    });
  }

  const compositionGuide = `
=== PRODUCTION_DATA ===
COORD_SYS: 0deg=North(+Z), 90deg=East(+X)
CAMERA: pos(${cam.x.toFixed(1)}, ${cam.z.toFixed(1)}), rotation(${cam.rotation.toFixed(1)}deg), focal_length(${focalLength}mm)
SHOT_SCALE_INFERRED: ${state.inferredShotScale || "Manual"}

LANDMARKS: ${JSON.stringify(state.landmarks.map(lm => ({ label: lm.label, desc: lm.description, pos: { x: lm.x, z: lm.z } })))}
SUBJECTS: ${JSON.stringify(subjectTags)}

INSTRUCTION: 
Create a comprehensive JSON Render Manifest. 
Include all subject details, environment descriptions, and spatial cues.
The 'cinematic_description' must be a detailed prose paragraph within the JSON.
The final output must be VALID JSON and strictly JSON.
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [...parts, { text: compositionGuide }] 
    },
    config: { 
      systemInstruction: "You are a Virtual Production Engine. Your task is to synthesize a 'Render Manifest' in JSON format. This manifest acts as the primary prompt for the image generator. It must be highly descriptive and structurally accurate to the provided coordinates and references.",
      responseMimeType: "application/json"
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 2000;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

