                       </p>
                    </div>
                    <div className="flex gap-4">
                      <button 
                        onClick={() => {
                          const link = document.createElement('a');
                          link.href = state.generatedImage!;
                          link.download = `studio-render-${Date.now()}.png`;
                          link.click();
                        }}
                        className="bg-white/10 hover:bg-white/20 border border-white/10 backdrop-blur-md text-white font-black px-8 py-4 rounded-xl flex items-center gap-3 transition-all"
                      >
                        <Download className="w-5 h-5" /> Download Still
                      </button>
                      <button 
                        disabled={state.isGeneratingVideo}
                        onClick={async () => {
                          setState(s => ({ ...s, isGeneratingVideo: true, videoStatus: 'Initializing Veo Engine...' }));
                          try {
                            const { url, cost } = await generateStudioVideo(state, state.draftPrompt, state.generatedImage!, (s) => setState(prev => ({ ...prev, videoStatus: s })));
                            setState(s => ({ 
                              ...s, 
                              generatedVideo: url, 
                              isGeneratingVideo: false, 
                              usage: { ...s.usage, totalSpent: s.usage.totalSpent + cost, video: s.usage.video + cost } 
                            }));
                          } catch (e) {
                            alert("Video synthesis failed. Please check credits.");
                            setState(s => ({ ...s, isGeneratingVideo: false }));
                          }
                        }}
                        className="bg-indigo-600 hover:bg-indigo-500 text-white font-black px-8 py-4 rounded-xl flex items-center gap-3 shadow-xl shadow-indigo-600/20 transition-all disabled:opacity-50"
                      >
                        {state.isGeneratingVideo ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
                        {state.isGeneratingVideo ? state.videoStatus : "Animate with Veo"}
                      </button>
                    </div>
                  </div>
               </div>

               {state.generatedVideo && (
                 <div className="absolute inset-0 z-[120] bg-black animate-in fade-in duration-1000">
                    <video src={state.generatedVideo} controls autoPlay loop className="w-full h-full object-contain" />
                    <button onClick={() => setState(s => ({ ...s, generatedVideo: undefined }))} className="absolute top-6 left-6 bg-white/10 hover:bg-white/20 p-4 rounded-2xl backdrop-blur-md border border-white/10 flex items-center gap-3 font-black uppercase text-xs">
                       <Minus className="w-4 h-4" /> Close Video Player
                    </button>
                 </div>
               )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

