};

export default App;

export type ReferenceType = 
  | 'background' 
  | 'character' 
  | 'costume' 
  | 'prop' 
  | 'accessories' 
  | 'pose';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface SubjectConfig {
  id: string;
  x: number;
  z: number;
  rotation: number;
  gaze: number;
  label: string;
  references: Partial<Record<ReferenceType, ReferenceImage>>;
}

export interface Landmark {
  id: string;
  label: string;
  description: string;
  x: number;
  z: number;
}

export interface CameraConfig {
  id: string;
  x: number;
  z: number;
  rotation: number;
  model: string;
  lens: string;
  verticalAngle: string;
}

export interface UsageStats {
  totalSpent: number;
  analysis: number;
  render: number;
  video: number;
  tokens: number;
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: {
    positions: boolean[];
  };
  subjects: SubjectConfig[];
  landmarks: Landmark[];
  cameras: CameraConfig[];
  activeCameraIndex: number;
  isGenerating: boolean;
  isGeneratingPrompt: boolean;
  isReviewingPrompt: boolean;
  isReviewingVideoPrompt: boolean;
  isGeneratingVideo: boolean;
  videoStatus?: string;
  draftPrompt: string;
  generatedImage?: string;
  generatedVideo?: string;
  plannerZoom: number;
  plannerOffset: { x: number; z: number };
  usage: UsageStats;
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Camera, Layers, Wand2, Loader2, X, Play, Download, 
  MonitorPlay, Users, Landmark as LandmarkIcon, 
  Sun, Copy, Check, Plus, Trash2, MapPin, ScanSearch,
  Maximize, Minus, Search, ChevronDown, ChevronUp, FileCode, Braces
} from 'lucide-react';
import { StudioState, ReferenceType, SubjectConfig, Landmark } from './types';
import { CAMERA_MODELS, LENSES, VERTICAL_ANGLES, COST_PER_IMAGE, COST_PER_VIDEO, PRODUCTION_SCALE_CONSTANT } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import LightRig from './components/LightRig';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo, analyzeBackground } from './services/geminiService';

